// Robust JSON extractor — handles markdown fences and partial truncation
const extractJSON = (text) => {
  const t = text.replace(/```json|```/g, "").trim();
  // Try direct parse first
  try { return JSON.parse(t); } catch(e1) {}
  // Try to find JSON object in the text
  const start = t.indexOf("{");
  const end = t.lastIndexOf("}");
  if (start >= 0 && end > start) {
    try { return JSON.parse(t.slice(start, end + 1)); } catch(e2) {}
  }
  // Try to auto-close incomplete JSON by counting braces
  let depth = 0, lastValid = -1;
  for (let i = 0; i < t.length; i++) {
    if (t[i] === "{") depth++;
    else if (t[i] === "}") { depth--; if (depth === 0) lastValid = i; }
  }
  if (lastValid > 0) {
    try { return JSON.parse(t.slice(0, lastValid + 1)); } catch(e3) {}
  }
  throw new Error("Could not parse JSON from response");
};

const store = (() => {
  // ── Supabase backend (multi-user, real-time) ──────────────────────────────
  if (SUPA_URL && SUPA_ANON) {
    const headers = {
      "Content-Type": "application/json",
      "apikey": SUPA_ANON,
      "Authorization": `Bearer ${SUPA_ANON}`,
      "Prefer": "resolution=merge-duplicates"
    };
    const base = `${SUPA_URL}/rest/v1/ops_store`;

    // Wake up the Supabase free-tier database on first load
    fetch(`${base}?key=eq.__ping&select=key`, { headers })
      .then(() => { console.log("[ZT] Supabase connected"); })
      .catch(() => {});

    // Subscribe to real-time changes and reload window.storage keys
    const ws = new WebSocket(
      `${SUPA_URL.replace("https","wss")}/realtime/v1/websocket?apikey=${SUPA_ANON}&vsn=1.0.0`
    );
    ws.onopen = () => {
      ws.send(JSON.stringify({ topic:"realtime:public:ops_store", event:"phx_join", payload:{}, ref:"1" }));
    };
    ws.onmessage = (e) => {
      try {
        const msg = JSON.parse(e.data);
        if (msg.event === "INSERT" || msg.event === "UPDATE") {
          const { key, value } = msg.payload?.record || {};
          if (key && value) window.__ztCache = window.__ztCache || {};
          if (key) { window.__ztCache[key] = JSON.parse(value); }
        }
      } catch {}
    };

    return {
      async get(k) {
        try {
          if (window.__ztCache?.[k] !== undefined) return window.__ztCache[k];
          const r = await fetch(`${base}?key=eq.${encodeURIComponent(k)}&select=value`, { headers });
          const rows = await r.json();
          const val = rows?.[0] ? JSON.parse(rows[0].value) : null;
          window.__ztCache = window.__ztCache || {};
          window.__ztCache[k] = val;
          return val;
        } catch { return null; }
      },
      async set(k, v) {
        try {
          window.__ztCache = window.__ztCache || {};
          window.__ztCache[k] = v;
          // Get current session for user_id scoping (enables per-user RLS)
          const sess = (() => { try { return JSON.parse(localStorage.getItem("zt-session")||"{}"); } catch { return {}; } })();
          const userId = sess?.user?.id || "anonymous";
          const userToken = sess?.access_token;
          // Use user token for authenticated requests when available
          const authHeaders = userToken
            ? { ...headers, "Authorization": `Bearer ${userToken}` }
            : headers;
          const upsertHeaders = { ...authHeaders, "Prefer": "return=minimal,resolution=merge-duplicates" };
          const body = JSON.stringify({ key: k, value: JSON.stringify(v), user_id: userId, updated_at: new Date().toISOString() });
          const res = await fetch(`${base}?on_conflict=key`, { method: "POST", headers: upsertHeaders, body });
          if (!res.ok) {
            await fetch(`${base}?key=eq.${encodeURIComponent(k)}`, {
              method: "PATCH",
              headers: { ...authHeaders, "Prefer": "return=minimal" },
              body: JSON.stringify({ value: JSON.stringify(v), updated_at: new Date().toISOString() })
            });
          }
        } catch {}
      }
    };
  }

  // ── localStorage fallback (single-user / preview mode) ───────────────────
  return {
    async get(k) { try { const v = localStorage.getItem("zt-" + k); return v ? JSON.parse(v) : null; } catch { return null; } },
    async set(k, v) { try { localStorage.setItem("zt-" + k, JSON.stringify(v)); } catch {} }
  };
})();

// ─── ZIKSATECH SEED DATA (from Ops Center spreadsheet) ───────────────────────
const BURDEN = { fica: 0.0765, futa: 0.006, futaCap: 7000, suta: 0.027, sutaCap: 9000, wc: 0.005, health: 7200, retire: 0.03, other: 0.015, hoursPerYear: 1920 };

// ─── CANONICAL COST HELPER ──────────────────────────────────────────────────
// Single source of truth for annual cost of any employee/contractor.
// All modules should call this instead of rolling their own formulas.
function getEmployeeCost(r) {
  if (!r) return 0;
  if (r.type === "Contractor") {
    // C2C: we pay fixedRate/hr. Zero employer burden.
    const hrs = Math.round((+r.util || 0) * BURDEN.hoursPerYear);
    return (+r.fixedRate || 0) * hrs;
  }
  // FTE: base = LCA wage (revenue_share) or base salary (fixed)
  const isRevShare = r.compType === "revenue_share";
  const sal = isRevShare ? (+r.lcaWage || +r.baseSalary || 0) : (+r.baseSalary || 0);
  const fica  = sal * BURDEN.fica;
  const futa  = BURDEN.futa  * Math.min(sal, BURDEN.futaCap);
  const suta  = BURDEN.suta  * Math.min(sal, BURDEN.sutaCap);
  const wc    = sal * BURDEN.wc;
  const ret   = sal * BURDEN.retire;
  const oth   = sal * BURDEN.other;
  const k401  = +r.contrib401k || 0;
  // TYPE 1 (fixed salary): company pays health. TYPE 2 (rev share): no health.
  const ins   = isRevShare ? 0 : (+r.insurance || BURDEN.health);
  const employerBurden = fica + futa + suta + wc + ret + oth + ins + k401;
  // Revenue share bonus (if applicable)
  let bonus = 0;
  if (isRevShare && +r.lcaWage > 0 && +r.revShare > 0) {
    const hrs = Math.round((+r.util || 0) * BURDEN.hoursPerYear);
    const lcaBurden = sal*(BURDEN.fica+BURDEN.wc+BURDEN.retire+BURDEN.other) + BURDEN.futa*Math.min(sal,BURDEN.futaCap) + BURDEN.suta*Math.min(sal,BURDEN.sutaCap);
    const loadedHr = (sal + lcaBurden) / hrs;
    const poolHr   = (+r.billRate || 0) * (+r.revShare);
    bonus = Math.max(0, (poolHr - loadedHr) * hrs);
  }
  return sal + employerBurden + bonus;
}

// Monthly version
function getEmployeeCostMonthly(r) { return getEmployeeCost(r) / 12; }

