        {tab==="adpstubs"   && <ADPPayStubs    {...shared} authProfile={authProfile} />}
        {tab==="reconcile"  && <ReconcileReport {...shared} authProfile={authProfile} />}
        {tab==="bankanalyzer" && <BankAnalyzer authProfile={authProfile}/>}
