// CONSULTANT HUB — Tax Tips, Visa Guidance & Company News
// ═══════════════════════════════════════════════════════════════════════
function ConsultantHub({ roster, authProfile }) {
  const [activeVisa, setActiveVisa] = useState("H-1B");
  const [section, setSection] = useState("tax");
  const visaTypes = Object.keys(CH_VISA_INFO);
  const vd = CH_VISA_INFO[activeVisa];
  const tips = CH_TIPS.filter(t => t[0] === activeVisa);
  return (
    <div>
      <PH title="Consultant Hub" sub={"Tax Savings \u00b7 Visa Guidance \u00b7 Company News \u2014 2025 Tax Year"}/>
      <div style={{display:"flex",gap:4,marginBottom:20,background:"#060d1c",borderRadius:10,padding:4,border:"1px solid #1a2d45"}}>
        {[["tax","\uD83D\uDCB0 Tax Tips & Savings"],["news","\uD83D\uDCF0 Company News"]].map(([id,lbl])=>(
          <button key={id} onClick={()=>setSection(id)}
            style={{flex:1,padding:"9px 16px",borderRadius:7,border:"none",cursor:"pointer",fontSize:13,fontWeight:700,
              background:section===id?"linear-gradient(135deg,#0369a1,#0284c7)":"transparent",
              color:section===id?"#fff":"#475569"}}>
            {lbl}
          </button>
        ))}
      </div>
      {section==="tax" && (
        <div>
          <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:16}}>
            {visaTypes.map(v=>(
              <button key={v} onClick={()=>setActiveVisa(v)}
                style={{padding:"6px 14px",borderRadius:20,border:"1px solid",cursor:"pointer",fontSize:12,fontWeight:600,
                  background:activeVisa===v?"linear-gradient(135deg,#0369a1,#0284c7)":"#060d1c",
                  borderColor:activeVisa===v?"#0369a1":"#1a2d45",
                  color:activeVisa===v?"#fff":"#475569"}}>
                {CH_VISA_INFO[v].icon} {v}
              </button>
            ))}
          </div>
          <div style={{padding:"12px 16px",background:"#0c2340",border:"1px solid #0369a1",borderRadius:10,marginBottom:14,display:"flex",flexWrap:"wrap",gap:20}}>
            <div>
              <div style={{fontSize:10,color:"#3d5a7a",textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:3}}>Filing Deadline</div>
              <div style={{fontSize:13,fontWeight:700,color:"#f87171"}}>\u23f0 {vd.deadline}</div>
            </div>
            <div>
              <div style={{fontSize:10,color:"#3d5a7a",textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:3}}>Tax Form</div>
              <div style={{fontSize:13,fontWeight:600,color:"#38bdf8"}}>\uD83D\uDCC4 {vd.form}</div>
            </div>
          </div>
          <div style={{padding:"8px 14px",background:"#0a1120",border:"1px solid #1a2d45",borderRadius:8,marginBottom:14,fontSize:11,color:"#334155"}}>
            \u26a0\ufe0f General info for 2025 tax year only. Consult a qualified CPA or tax attorney for advice specific to your situation.
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:10}}>
            {tips.map((tip,i)=>(
              <div key={i} style={{background:tip[5],border:"1px solid "+tip[4]+"44",borderRadius:10,padding:"14px 16px"}}>
                <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:8}}>
                  <div style={{fontSize:13,fontWeight:700,color:tip[4],lineHeight:1.3,flex:1,paddingRight:8}}>{tip[1]}</div>
                  <span style={{background:tip[4]+"22",color:tip[4],fontSize:9,fontWeight:800,padding:"2px 7px",borderRadius:10,whiteSpace:"nowrap",textTransform:"uppercase",flexShrink:0}}>{tip[3]}</span>
                </div>
                <div style={{fontSize:12,color:"#94a3b8",lineHeight:1.6}}>{tip[2]}</div>
              </div>
            ))}
          </div>
        </div>
      )}
      {section==="news" && (
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          {CH_NEWS.map((n,i)=>(
            <div key={i} style={{background:"#060d1c",border:"1px solid #1a2d45",borderRadius:12,padding:"16px 20px",display:"flex",gap:16}}>
              <div style={{flexShrink:0,minWidth:52,textAlign:"center"}}>
                <div style={{fontSize:10,fontWeight:800,color:CH_TAG_COLORS[n.tag]||"#64748b",background:(CH_TAG_COLORS[n.tag]||"#64748b")+"22",borderRadius:6,padding:"3px 6px",marginBottom:4}}>{n.tag}</div>
                <div style={{fontSize:10,color:"#334155"}}>{n.date}</div>
              </div>
              <div style={{flex:1}}>
                <div style={{fontSize:11,color:"#3d5a7a",marginBottom:4}}>{n.cat}</div>
                <div style={{fontSize:14,fontWeight:700,color:"#e2e8f0",marginBottom:6}}>{n.title}</div>
                <div style={{fontSize:12,color:"#64748b",lineHeight:1.6}}>{n.body}</div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

