function ConsultantProfitOpt({ roster, clients, finInvoices, tsHours, crmDeals, authProfile }) {
  const [loading, setLoading] = useState(false);
  const [recs,    setRecs]    = useState(null);
  const [selId,   setSelId]   = useState(null);
  const fmt  = n => "$" + Math.round(n).toLocaleString();
  const fmtK = n => n>=1000 ? "$"+Math.round(n/1000)+"K" : fmt(n);

  // Build consultant portfolio data
  const consultantData = roster.map(r => {
    const annualCost = getEmployeeCost(r);
    const hrs        = MONTHS.reduce((s,_,mi) => s+(tsHours[r.id]?.[mi]||0), 0);
    const revenue    = hrs * (r.billRate||0);
    const margin     = revenue > 0 ? Math.round((revenue-annualCost)/revenue*100) : 0;
    const util       = Math.round((r.util||0)*100);
    // Market rate gap: compare to RATE_BOOK average for senior SAP
    const marketRate = r.role?.toLowerCase().includes("brim") ? 155
      : r.role?.toLowerCase().includes("successfactor") ? 130
      : r.role?.toLowerCase().includes("data") ? 150
      : r.role?.toLowerCase().includes("pm") ? 160 : 140;
    const rateGap    = marketRate - (r.billRate||0);
    const rateUpliftAnn = Math.round((r.util||0) * 1920 * Math.max(0, rateGap));
    // Client assignment: is this client growing or shrinking?
    const clientObj  = clients.find(cl => cl.name === r.client || cl.id === r.client);
    return {
      id: r.id, name: r.name, role: r.role, type: r.type,
      client: r.client, billRate: r.billRate||0, util,
      annualCost, revenue, margin, marketRate, rateGap, rateUpliftAnn,
      clientHealth: clientObj?.healthScore || "green",
    };
  }).sort((a,b) => a.margin - b.margin);

  const totalOptPotential = consultantData.reduce((s,r) => s+r.rateUpliftAnn, 0);

  const runAI = async () => {
    setLoading(true);
    const top5 = consultantData.slice(0,5).map(r =>
      `${r.name}: ${r.util}% util, $${r.billRate}/hr, ${r.margin}% margin, client=${r.client}, gap=$${r.rateGap}/hr`
    ).join("\n");
    try {
      const resp = await fetch("/api/claude", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({
          model:"claude-sonnet-4-20250514", max_tokens:800,
          system:"You are a consultant portfolio optimization AI for a SAP consulting firm. Give specific, actionable, data-driven recommendations. Be direct and quantify impact.",
          messages:[{ role:"user", content:
`Optimize this consultant portfolio for maximum margin. Here are the 5 lowest-margin consultants:
${top5}

Total rate-uplift potential: ${fmtK(totalOptPotential)}/year

Respond ONLY with this JSON:
{
  "headline": "one sentence portfolio assessment",
  "recommendations": [
    {"consultant":"name","action":"specific move","impact":"$X uplift or Y% margin gain","timeline":"30/60/90 days"},
    {"consultant":"name","action":"...","impact":"...","timeline":"..."},
    {"consultant":"name","action":"...","impact":"...","timeline":"..."}
  ],
  "topMove": "single highest-ROI action this month"
}` }]
        })
      });
      const data = await resp.json();
      const text = data.content?.[0]?.text||"{}";
      setRecs(extractJSON(text));
    } catch(e) { setRecs({headline:"Analysis complete — see data below.",recommendations:[],topMove:""}) }
    setLoading(false);
  };

  return (
    <div>
      <PH title="📈 Consultant Profit Optimizer" sub="Rate benchmarking · margin analysis · portfolio optimization recommendations"/>

      {/* KPIs */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:18}}>
        {[
          {l:"Total Headcount",   v:roster.length,                                 c:"#38bdf8"},
          {l:"Avg Margin",        v:Math.round(consultantData.reduce((s,r)=>s+r.margin,0)/Math.max(1,consultantData.length))+"%", c:"#34d399"},
          {l:"Rate Uplift Potential", v:fmtK(totalOptPotential)+"/yr",             c:"#f59e0b"},
          {l:"Below Market Rate", v:consultantData.filter(r=>r.rateGap>0).length+" consultants", c:"#f87171"},
        ].map(k=>(
          <div key={k.l} className="card" style={{padding:"12px 14px",textAlign:"center"}}>
            <div style={{fontSize:18,fontWeight:800,color:k.c,fontFamily:"'DM Mono',monospace"}}>{k.v}</div>
            <div style={{fontSize:10,color:"#475569",marginTop:2}}>{k.l}</div>
          </div>
        ))}
      </div>

      {/* AI Recommendations */}
      {recs ? (
        <div className="card" style={{padding:"18px 20px",marginBottom:14,border:"1px solid #0369a144"}}>
          <div style={{fontSize:13,fontWeight:700,color:"#38bdf8",marginBottom:12}}>🤖 AI Recommendations</div>
          {recs.topMove && (
            <div style={{padding:"10px 14px",background:"#021f14",border:"1px solid #34d39944",borderRadius:8,marginBottom:12,fontSize:12,color:"#34d399"}}>
              ⚡ Top Move: <strong>{recs.topMove}</strong>
            </div>
          )}
          {recs.headline && <div style={{fontSize:11,color:"#94a3b8",marginBottom:12,fontStyle:"italic"}}>{recs.headline}</div>}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10}}>
            {(recs.recommendations||[]).map((r,i)=>(
              <div key={i} style={{padding:"12px 14px",background:"#070c18",borderRadius:8,border:"1px solid #1a2d45"}}>
                <div style={{fontSize:11,fontWeight:700,color:"#e2e8f0",marginBottom:4}}>{r.consultant}</div>
                <div style={{fontSize:11,color:"#94a3b8",marginBottom:6}}>{r.action}</div>
                <div style={{fontSize:10,color:"#34d399",fontFamily:"monospace",marginBottom:4}}>💰 {r.impact}</div>
                <div style={{fontSize:9,color:"#3d5a7a"}}>⏱ {r.timeline}</div>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div style={{marginBottom:14}}>
          <button className="btn bp" style={{fontSize:13,padding:"10px 24px"}} onClick={runAI} disabled={loading}>
            {loading?"⏳ Analyzing Portfolio...":"🤖 Run AI Portfolio Analysis"}
          </button>
          <span style={{fontSize:10,color:"#334155",marginLeft:12}}>Analyzes all consultants for rate gaps, utilization, and margin optimization</span>
        </div>
      )}

      {/* Consultant table */}
      <div className="card" style={{overflow:"auto"}}>
        <div style={{display:"grid",gridTemplateColumns:"2fr 1.2fr 80px 80px 80px 80px 1fr",padding:"8px 14px",
          borderBottom:"1px solid #1a2d45"}}>
          {["Consultant","Role","Rate","Market","Gap","Margin","Action"].map(h=>(
            <div key={h} className="th" style={{fontSize:10}}>{h}</div>
          ))}
        </div>
        {consultantData.map(r=>(
          <div key={r.id} style={{display:"grid",gridTemplateColumns:"2fr 1.2fr 80px 80px 80px 80px 1fr",
            padding:"8px 14px",borderBottom:"1px solid #070c18",
            background:selId===r.id?"#0a1a2e":"transparent",cursor:"pointer"}}
            onClick={()=>setSelId(selId===r.id?null:r.id)}>
            <div>
              <div style={{fontSize:12,fontWeight:600,color:"#cbd5e1"}}>{r.name}</div>
              <div style={{fontSize:10,color:"#3d5a7a"}}>{r.client} · {r.util}% util</div>
            </div>
            <div style={{fontSize:10,color:"#64748b",alignSelf:"center"}}>{r.role?.slice(0,25)}</div>
            <div style={{fontSize:12,fontFamily:"monospace",color:"#38bdf8",alignSelf:"center"}}>${r.billRate}</div>
            <div style={{fontSize:12,fontFamily:"monospace",color:"#64748b",alignSelf:"center"}}>${r.marketRate}</div>
            <div style={{fontSize:12,fontFamily:"monospace",
              color:r.rateGap>0?"#f87171":"#34d399",alignSelf:"center",fontWeight:700}}>
              {r.rateGap>0?"+$"+r.rateGap:"✓"}
            </div>
            <div style={{alignSelf:"center"}}>
              <span style={{fontSize:11,fontWeight:700,
                color:r.margin>=30?"#34d399":r.margin>=15?"#f59e0b":"#f87171"}}>
                {r.margin}%
              </span>
            </div>
            <div style={{fontSize:10,color:"#f59e0b",alignSelf:"center"}}>
              {r.rateGap>0 ? `↑ +${fmtK(r.rateUpliftAnn)}/yr` : r.margin<20?"📊 Review mix":"✅ Optimized"}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

// =============================================================================
// 🏢 CLIENT 360 INTELLIGENCE  (Phase 2)
// =============================================================================
function Client360Intelligence({ clients, finInvoices, finPayments, crmDeals, roster, contracts, projects, authProfile }) {
  const [selClient, setSelClient] = useState(clients[0]?.id || "");
  const [tab,       setTab]       = useState("overview");
  const [loading,   setLoading]   = useState({});
  const [intel,     setIntel]     = useState({});
  const fmt  = n => "$"+Math.round(n||0).toLocaleString();
  const fmtK = n => (n||0)>=1000?"$"+Math.round((n||0)/1000)+"K":fmt(n);
  const TODAY = new Date().toISOString().split("T")[0];

  const cl = clients.find(c=>c.id===selClient) || clients[0] || {};
  const ci = intel[selClient]?.overview;
  const upsell = intel[selClient]?.upsell;
  const renewal = intel[selClient]?.renewal;

  // ── Client metrics ───────────────────────────────────────────────────────
  const clInvoices  = finInvoices.filter(i=>i.clientId===selClient||i.clientName===cl.name);
  const clPayments  = finPayments.filter(p=>p.clientId===selClient);
  const clDeals     = crmDeals.filter(d=>d.clientId===selClient||d.clientName===cl.name||d.company===cl.name);
  const clConsults  = roster.filter(r=>r.clientId===selClient||r.client===cl.name);
  const clContracts = contracts?.filter(c=>c.clientId===selClient)||[];
  const clProjects  = projects?.filter(p=>p.clientId===selClient)||[];

  const totalBilled = clInvoices.reduce((s,i)=>s+(i.amount||0),0);
  const totalPaid   = clPayments.reduce((s,p)=>s+(p.amount||0),0);
  const openAR      = clInvoices.filter(i=>i.status!=="paid").reduce((s,i)=>s+(i.amount||0)-(i.paidAmount||0),0);
  const avgDSO      = clInvoices.length > 0
    ? Math.round(clInvoices.reduce((s,i)=>{ const d=(new Date(i.paidDate||TODAY)-new Date(i.date))/86400000; return s+(d>0?d:0); },0)/clInvoices.length)
    : 0;

  const nearestRenewal = clContracts.sort((a,b)=>new Date(a.endDate||"2099")-new Date(b.endDate||"2099"))[0];
  const renewalDays = nearestRenewal?.endDate
    ? Math.ceil((new Date(nearestRenewal.endDate)-new Date())/86400000)
    : 999;
  const churnRisk  = renewalDays<30?"HIGH":renewalDays<90?"MEDIUM":"LOW";
  const churnColor = churnRisk==="HIGH"?"#f87171":churnRisk==="MEDIUM"?"#f59e0b":"#34d399";

  const buildClientContext = () => `
Client: ${cl.name} | Vertical: ${cl.vertical||"—"} | Health: ${cl.healthScore||"green"}
Total billed: ${fmtK(totalBilled)} | Open AR: ${fmtK(openAR)} | Avg DSO: ${avgDSO} days
Consultants deployed: ${clConsults.length} (${clConsults.map(r=>r.name+" "+r.role).slice(0,4).join(", ")})
Open deals: ${clDeals.filter(d=>!["closed-won","closed_won","closed-lost","closed_lost"].includes(d.stage)).length}
Active projects: ${clProjects.filter(p=>p.status==="active").length}
Next renewal: ${nearestRenewal?.endDate||"no date"} (${renewalDays<999?renewalDays+" days":"no contract"})
Annual contract value: ${fmtK(cl.annualValue||cl.contractValue||0)}
Notes: ${cl.notes||"SAP consulting engagement"}
`;

  // ── AI runners ───────────────────────────────────────────────────────────
  const runAI = async (type) => {
    setLoading(l=>({...l,[`${selClient}-${type}`]:true}));
    const ctx = buildClientContext();
    let prompt = "";
    let schema = "";

    if (type === "overview") {
      prompt = `Analyze this client for strategic intelligence:
${ctx}`;
      schema = `{"executiveSummary":"2-sentence client health + relationship summary","growthOpportunities":["specific upsell 1","upsell 2","upsell 3"],"riskFactors":["risk 1","risk 2"],"nextActions":["action this week","action this month"],"churnSignals":"renewal/churn risk assessment","relationshipScore":0-100,"budgetCycleIntel":"when this client typically approves budgets and what drives their decisions"}`;
    } else if (type === "upsell") {
      prompt = `Generate upsell and expansion intelligence for this client:
${ctx}`;
      schema = `{"headline":"one-sentence upsell opportunity summary","topPlay":{"service":"specific SAP service to sell","why":"why this client needs it now","estimatedValue":"$XXX,000","timing":"when to pitch","approach":"how to position it"},"expansionPlays":[{"play":"...","revenue":"...","effort":"LOW|MEDIUM|HIGH"},{"play":"...","revenue":"...","effort":"..."},{"play":"...","revenue":"...","effort":"..."}],"stakeholderStrategy":"who to target for expansion conversations","competitorRisk":"what competitor might be trying to steal this client","executivePitch":"two sentences Manju can say to the CIO/VP to open expansion conversation"}`;
    } else if (type === "renewal") {
      prompt = `Generate a renewal and retention playbook for this client:
${ctx}
Days to renewal: ${renewalDays}`;
      schema = `{"urgency":"HIGH|MEDIUM|LOW","headline":"one-sentence renewal situation assessment","renewalHealth":0-100,"timeline":[{"week":"Week 1","action":"..."},{"week":"Week 2","action":"..."},{"week":"Week 3","action":"..."},{"week":"Week 4","action":"..."}],"rateIncreaseStrategy":"how much to ask for and how to justify it","championMessage":"what to say to your champion to lock in renewal","blockerStrategy":"how to handle procurement or budget objections","walkAwayLine":"minimum terms Ziksatech should accept"}`;
    }

    try {
      const resp = await fetch("/api/claude", { method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:2000,
          system:`You are a strategic client intelligence AI for Ziksatech, a WBE SAP consulting firm in DFW. Give specific, practical intelligence.`,
          messages:[{role:"user",content:`${prompt}

Respond ONLY with JSON (no markdown):
${schema}`}]
        })
      });
      const data = await resp.json();
      const parsed = extractJSON(data.content?.[0]?.text||"{}");
      setIntel(prev=>({...prev, [selClient]:{...(prev[selClient]||{}), [type]:parsed}}));
    } catch(e) { setIntel(prev=>({...prev, [selClient]:{...(prev[selClient]||{}), [type]:{error:e.message}}})); }
    setLoading(l=>({...l,[`${selClient}-${type}`]:false}));
  };

  const TABS = [
    {id:"overview", label:"📊 Overview"},
    {id:"upsell",   label:"🚀 Upsell Intel"},
    {id:"renewal",  label:"🔄 Renewal Playbook"},
  ];

  return (
    <div>
      <PH title="🏢 Client 360 Intelligence" sub="Full relationship view · upsell intelligence · renewal playbook · churn detection"/>

      {/* Client selector */}
      <div style={{display:"flex",gap:6,marginBottom:16,flexWrap:"wrap"}}>
        {clients.map(c=>(
          <button key={c.id} onClick={()=>setSelClient(c.id)}
            className={`btn ${selClient===c.id?"bp":"bg"}`} style={{fontSize:11}}>
            {c.name}
          </button>
        ))}
      </div>

      {/* Header KPIs */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:10,marginBottom:14}}>
        {[
          {l:"Total Billed",    v:fmtK(totalBilled),             c:"#38bdf8"},
          {l:"Open AR",         v:fmtK(openAR),                   c:openAR>10000?"#f87171":"#34d399"},
          {l:"Avg DSO",         v:avgDSO+" days",                 c:avgDSO>45?"#f87171":"#34d399"},
          {l:"Consultants",     v:clConsults.length+" deployed",  c:"#a78bfa"},
          {l:"Renewal Risk",    v:churnRisk,                       c:churnColor},
        ].map(k=>(
          <div key={k.l} className="card" style={{padding:"10px 14px",textAlign:"center"}}>
            <div style={{fontSize:16,fontWeight:800,color:k.c,fontFamily:"'DM Mono',monospace"}}>{k.v}</div>
            <div style={{fontSize:10,color:"#475569",marginTop:2}}>{k.l}</div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div style={{display:"flex",gap:4,marginBottom:14,borderBottom:"1px solid #1a2d45",paddingBottom:4}}>
        {TABS.map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)}
            style={{padding:"7px 16px",borderRadius:"6px 6px 0 0",border:"none",fontSize:11,fontWeight:600,cursor:"pointer",
              background:tab===t.id?"#0c2340":"transparent",color:tab===t.id?"#38bdf8":"#475569",
              borderBottom:tab===t.id?"2px solid #0ea5e9":"2px solid transparent"}}>
            {t.label}
          </button>
        ))}
      </div>

      {/* ── OVERVIEW TAB ── */}
      {tab==="overview" && (
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
          {/* Left: relationship data */}
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            <div className="card" style={{padding:"14px 16px"}}>
              <div className="section-hdr">Client Profile</div>
              {[
                ["Vertical",        cl.vertical||"—"],
                ["Health Score",    cl.healthScore||"green"],
                ["Next Renewal",    nearestRenewal?.endDate||"—", renewalDays<90?churnColor:"#94a3b8"],
                ["Days to Renewal", renewalDays>900?"No date set":`${renewalDays} days`,
                  renewalDays<30?"#f87171":renewalDays<90?"#f59e0b":"#34d399"],
                ["Engagement Type", clContracts[0]?.type||cl.engagementType||"Staff Augmentation"],
                ["Active Projects", clProjects.filter(p=>p.status==="active").length],
                ["Won Deals",       clDeals.filter(d=>d.stage==="closed-won"||d.stage==="closed_won").length],
              ].map(([l,v,col])=>(
                <div key={l} style={{display:"flex",justifyContent:"space-between",padding:"5px 0",borderBottom:"1px solid #0a1626"}}>
                  <span style={{fontSize:11,color:"#64748b"}}>{l}</span>
                  <span style={{fontSize:11,fontWeight:600,color:col||"#e2e8f0"}}>{v}</span>
                </div>
              ))}
            </div>
            <div className="card" style={{padding:"14px 16px"}}>
              <div className="section-hdr">Deployed Team ({clConsults.length})</div>
              {clConsults.length===0 ? <div style={{fontSize:11,color:"#334155"}}>No consultants assigned</div>
              : clConsults.map(r=>(
                <div key={r.id} style={{display:"flex",justifyContent:"space-between",padding:"5px 0",borderBottom:"1px solid #0a1626"}}>
                  <div>
                    <div style={{fontSize:11,fontWeight:600,color:"#cbd5e1"}}>{r.name}</div>
                    <div style={{fontSize:9,color:"#3d5a7a"}}>{r.role}</div>
                  </div>
                  <span style={{fontSize:11,color:"#38bdf8",fontFamily:"monospace"}}>${r.billRate}/hr</span>
                </div>
              ))}
            </div>
          </div>

          {/* Right: AI overview */}
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {ci ? (
              <>
                <div className="card" style={{padding:"14px 16px",border:"1px solid #0369a144"}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#38bdf8"}}>🤖 AI Executive Summary</div>
                    {ci.relationshipScore!==undefined&&(
                      <div style={{fontSize:18,fontWeight:800,color:ci.relationshipScore>=70?"#34d399":ci.relationshipScore>=50?"#f59e0b":"#f87171",fontFamily:"monospace"}}>{ci.relationshipScore}<span style={{fontSize:10,color:"#475569"}}>/100</span></div>
                    )}
                  </div>
                  <p style={{fontSize:12,color:"#94a3b8",lineHeight:1.6,margin:0}}>{ci.executiveSummary}</p>
                  {ci.budgetCycleIntel&&<div style={{marginTop:8,padding:"6px 10px",background:"#0c1a2e",borderRadius:5,fontSize:10,color:"#38bdf8"}}><strong>💰 Budget Intel:</strong> {ci.budgetCycleIntel}</div>}
                </div>
                {ci.growthOpportunities?.length>0&&(
                  <div className="card" style={{padding:"14px 16px",border:"1px solid #34d39933"}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#34d399",marginBottom:8}}>🚀 Growth Opportunities</div>
                    {ci.growthOpportunities.map((o,i)=><div key={i} style={{fontSize:11,color:"#94a3b8",padding:"4px 0",borderBottom:"1px solid #0a1626"}}>💡 {o}</div>)}
                  </div>
                )}
                {ci.riskFactors?.length>0&&(
                  <div className="card" style={{padding:"14px 16px",border:"1px solid #f8717133"}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#f87171",marginBottom:8}}>⚠ Risk Factors</div>
                    {ci.riskFactors.map((r,i)=><div key={i} style={{fontSize:11,color:"#94a3b8",padding:"4px 0",borderBottom:"1px solid #0a1626"}}>🔴 {r}</div>)}
                  </div>
                )}
                {ci.nextActions?.length>0&&(
                  <div className="card" style={{padding:"14px 16px"}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#f59e0b",marginBottom:8}}>⚡ Next Actions</div>
                    {ci.nextActions.map((a,i)=><div key={i} style={{fontSize:11,color:"#94a3b8",padding:"4px 0",borderBottom:"1px solid #0a1626"}}>→ {a}</div>)}
                  </div>
                )}
              </>
            ) : (
              <div className="card" style={{padding:"24px",textAlign:"center"}}>
                <div style={{fontSize:12,color:"#3d5a7a",marginBottom:12}}>Get AI-powered intelligence for {cl.name}</div>
                <button className="btn bp" style={{fontSize:12}} onClick={()=>runAI("overview")} disabled={loading[`${selClient}-overview`]}>
                  {loading[`${selClient}-overview`]?"⏳ Analyzing...":"🤖 Generate Client Intelligence"}
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* ── UPSELL TAB ── */}
      {tab==="upsell" && (
        <div>
          {!upsell && (
            <div className="card" style={{padding:"32px",textAlign:"center"}}>
              <div style={{fontSize:32,marginBottom:10}}>🚀</div>
              <div style={{fontSize:13,color:"#94a3b8",marginBottom:16}}>
                AI analyzes {cl.name}'s SAP landscape, budget cycles, and expansion signals to identify the highest-value upsell plays
              </div>
              <button className="btn bp" style={{fontSize:13,padding:"10px 28px"}} onClick={()=>runAI("upsell")} disabled={loading[`${selClient}-upsell`]}>
                {loading[`${selClient}-upsell`]?"⏳ Analyzing upsell opportunities...":"🚀 Generate Upsell Intelligence"}
              </button>
            </div>
          )}
          {upsell && !upsell.error && (
            <div>
              {/* Top upsell play */}
              <div className="card" style={{padding:"18px 20px",border:"1px solid #34d39944",marginBottom:14}}>
                <div style={{fontSize:11,fontWeight:700,color:"#34d399",marginBottom:10}}>🏆 Top Upsell Play — {upsell.topPlay?.service}</div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8,marginBottom:10}}>
                  {[
                    ["Service",   upsell.topPlay?.service,      "#38bdf8"],
                    ["Est Value", upsell.topPlay?.estimatedValue,"#34d399"],
                    ["Timing",    upsell.topPlay?.timing,        "#f59e0b"],
                    ["Effort",    "MEDIUM",                       "#a78bfa"],
                  ].map(([l,v,col])=>(
                    <div key={l} style={{padding:"8px 10px",background:"#040a14",borderRadius:6}}>
                      <div style={{fontSize:9,color:"#3d5a7a",marginBottom:2}}>{l}</div>
                      <div style={{fontSize:11,color:col,fontWeight:600}}>{v||"—"}</div>
                    </div>
                  ))}
                </div>
                <div style={{fontSize:11,color:"#94a3b8",lineHeight:1.5,marginBottom:8}}><strong style={{color:"#e2e8f0"}}>Why: </strong>{upsell.topPlay?.why}</div>
                <div style={{padding:"8px 12px",background:"#0c2340",borderRadius:6,border:"1px solid #0369a144"}}>
                  <div style={{fontSize:10,color:"#3d5a7a",marginBottom:3,textTransform:"uppercase"}}>📣 Executive Pitch</div>
                  <div style={{fontSize:12,color:"#38bdf8",fontStyle:"italic"}}>"{upsell.executivePitch}"</div>
                </div>
              </div>

              {/* Expansion plays grid */}
              {(upsell.expansionPlays||[]).length>0&&(
                <div className="card" style={{padding:"16px 18px",marginBottom:14}}>
                  <div style={{fontSize:11,fontWeight:700,color:"#e2e8f0",marginBottom:10}}>📋 All Expansion Plays</div>
                  {upsell.expansionPlays.map((p,i)=>(
                    <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"8px 0",borderBottom:"1px solid #0a1626"}}>
                      <div style={{flex:1}}>
                        <div style={{fontSize:11,color:"#e2e8f0",fontWeight:600}}>{p.play}</div>
                        <div style={{fontSize:9,color:"#64748b",marginTop:1}}>Effort: <span style={{color:p.effort==="LOW"?"#34d399":p.effort==="HIGH"?"#f87171":"#f59e0b"}}>{p.effort}</span></div>
                      </div>
                      <div style={{fontSize:12,fontWeight:700,color:"#34d399",fontFamily:"monospace"}}>{p.revenue}</div>
                    </div>
                  ))}
                </div>
              )}

              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div style={{padding:"10px 14px",background:"#0c1a2e",border:"1px solid #0369a144",borderRadius:8}}>
                  <div style={{fontSize:9,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase"}}>👥 Stakeholder Strategy</div>
                  <div style={{fontSize:11,color:"#94a3b8",lineHeight:1.4}}>{upsell.stakeholderStrategy}</div>
                </div>
                <div style={{padding:"10px 14px",background:"#1a0808",border:"1px solid #dc262644",borderRadius:8}}>
                  <div style={{fontSize:9,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase"}}>🥊 Competitor Risk</div>
                  <div style={{fontSize:11,color:"#f87171",lineHeight:1.4}}>{upsell.competitorRisk}</div>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* ── RENEWAL PLAYBOOK TAB ── */}
      {tab==="renewal" && (
        <div>
          {/* Renewal urgency banner */}
          <div style={{padding:"12px 16px",background:renewalDays<30?"#1a0808":renewalDays<90?"#1a1000":"#021f14",
            border:`1px solid ${churnColor}44`,borderRadius:10,marginBottom:14}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <div>
                <div style={{fontSize:12,fontWeight:700,color:churnColor}}>
                  {churnRisk==="HIGH"?"🔴 URGENT":churnRisk==="MEDIUM"?"🟡 ATTENTION NEEDED":"✅ STABLE"} — Renewal Risk: {churnRisk}
                </div>
                <div style={{fontSize:11,color:"#64748b",marginTop:2}}>
                  {renewalDays<999?`${renewalDays} days until renewal — ${nearestRenewal?.endDate}`:"No renewal date set"}
                </div>
              </div>
              <button className="btn bp" style={{fontSize:11}} onClick={()=>runAI("renewal")} disabled={loading[`${selClient}-renewal`]}>
                {loading[`${selClient}-renewal`]?"⏳...":"📖 Generate Renewal Playbook"}
              </button>
            </div>
          </div>

          {!renewal && !loading[`${selClient}-renewal`] && (
            <div className="card" style={{padding:"28px",textAlign:"center",color:"#475569",fontSize:12}}>
              Click "Generate Renewal Playbook" to get a week-by-week action plan to secure renewal
            </div>
          )}

          {renewal && !renewal.error && (
            <div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>
                <div style={{padding:"12px 16px",background:"#060d1c",border:`1px solid ${churnColor}44`,borderRadius:8}}>
                  <div style={{fontSize:9,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase"}}>Renewal Health</div>
                  <div style={{fontSize:24,fontWeight:800,color:churnColor,fontFamily:"monospace"}}>{renewal.renewalHealth}/100</div>
                  <div style={{fontSize:11,color:"#94a3b8",marginTop:4}}>{renewal.headline}</div>
                </div>
                <div style={{padding:"12px 16px",background:"#0c1a2e",border:"1px solid #0369a144",borderRadius:8}}>
                  <div style={{fontSize:9,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase"}}>💬 Champion Message</div>
                  <div style={{fontSize:11,color:"#38bdf8",fontStyle:"italic",lineHeight:1.5}}>"{renewal.championMessage}"</div>
                </div>
              </div>

              {/* 4-week timeline */}
              {(renewal.timeline||[]).length>0&&(
                <div className="card" style={{padding:"14px 16px",marginBottom:12}}>
                  <div style={{fontSize:11,fontWeight:700,color:"#e2e8f0",marginBottom:10}}>📅 Renewal Timeline</div>
                  <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8}}>
                    {renewal.timeline.map((t,i)=>(
                      <div key={i} style={{padding:"10px 12px",background:"#060d1c",borderRadius:8,border:"1px solid #1e3a5f"}}>
                        <div style={{fontSize:9,color:"#3d5a7a",fontWeight:700,marginBottom:4,textTransform:"uppercase"}}>{t.week}</div>
                        <div style={{fontSize:10,color:"#94a3b8",lineHeight:1.4}}>{t.action}</div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div style={{padding:"10px 14px",background:"#021f14",border:"1px solid #15803d44",borderRadius:8}}>
                  <div style={{fontSize:9,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase"}}>💰 Rate Increase Strategy</div>
                  <div style={{fontSize:11,color:"#34d399",lineHeight:1.4}}>{renewal.rateIncreaseStrategy}</div>
                </div>
                <div style={{padding:"10px 14px",background:"#1a0808",border:"1px solid #f8717144",borderRadius:8}}>
                  <div style={{fontSize:9,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase"}}>🚫 Walk-Away Line</div>
                  <div style={{fontSize:11,color:"#f87171",lineHeight:1.4}}>{renewal.walkAwayLine}</div>
                </div>
                <div style={{padding:"10px 14px",background:"#1a1000",border:"1px solid #d9770644",borderRadius:8,gridColumn:"1/-1"}}>
                  <div style={{fontSize:9,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase"}}>🛡 Blocker Strategy</div>
                  <div style={{fontSize:11,color:"#f59e0b",lineHeight:1.4}}>{renewal.blockerStrategy}</div>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}


// =============================================================================
// 🧩 KNOWLEDGE ENGINE  (Phase 2 — Institutional Learning)
// =============================================================================
function KnowledgeEngine({ crmDeals, proposals, roster, clients, authProfile }) {
  const [tab,      setTab]      = useState("ask");
  const [query,    setQuery]    = useState("");
  const [loading,  setLoading]  = useState(false);
  const [answer,   setAnswer]   = useState(null);
  const [history,  setHistory]  = useState(()=>{try{return JSON.parse(localStorage.getItem("zt-ke-history")||"[]");}catch{return [];}});
  const [patternLoading, setPatternLoading] = useState(false);
  const [patterns, setPatterns] = useState(null);
  const [playbookLoading, setPlaybookLoading] = useState(false);
  const [playbook, setPlaybook] = useState(null);
  const [selVertical, setSelVertical] = useState("Utilities");
  const [pricingLoading, setPricingLoading] = useState(false);
  const [pricing, setPricing] = useState(null);

  // ── Knowledge base from real data ────────────────────────────────────────
  const closedDeals = crmDeals.filter(d => d.stage==="closed-won"||d.stage==="closed_won"||d.stage==="closed-lost"||d.stage==="closed_lost");
  const wonDeals    = crmDeals.filter(d => d.stage==="closed-won"||d.stage==="closed_won");
  const lostDeals   = crmDeals.filter(d => d.stage==="closed-lost"||d.stage==="closed_lost");
  const winRate     = closedDeals.length > 0 ? Math.round(wonDeals.length/closedDeals.length*100) : 0;
  const avgDealSize = wonDeals.length > 0 ? Math.round(wonDeals.reduce((s,d)=>s+(d.value||0),0)/wonDeals.length) : 0;
  const pipelineVal = crmDeals.filter(d=>!["closed-won","closed_won","closed-lost","closed_lost"].includes(d.stage)).reduce((s,d)=>s+(d.value||0),0);

  const byVertical = {};
  crmDeals.forEach(d => {
    const v = clients.find(cl=>cl.name===d.clientName||cl.name===d.company)?.vertical || d.vertical || "Other";
    if (!byVertical[v]) byVertical[v] = {won:0,lost:0,active:0,vals:[],deals:[]};
    if (d.stage==="closed-won"||d.stage==="closed_won") { byVertical[v].won++; if(d.value) byVertical[v].vals.push(d.value); }
    else if (d.stage==="closed-lost"||d.stage==="closed_lost") byVertical[v].lost++;
    else byVertical[v].active++;
    byVertical[v].deals.push(d);
  });

  const verticals = Object.keys(byVertical).sort((a,b)=>(byVertical[b].won+byVertical[b].active)-(byVertical[a].won+byVertical[a].active));

  const buildDigest = () => JSON.stringify({
    totalDeals: crmDeals.length, wonDeals: wonDeals.length, lostDeals: lostDeals.length,
    winRate: winRate+"%", avgWonDealSize: "$"+Math.round(avgDealSize/1000)+"K",
    pipelineValue: "$"+Math.round(pipelineVal/1000)+"K",
    byVertical: Object.entries(byVertical).slice(0,8).map(([v,d])=>({
      vertical:v, won:d.won, lost:d.lost, active:d.active,
      winRate: d.won+d.lost>0?Math.round(d.won/(d.won+d.lost)*100)+"%":"N/A",
      avgVal: d.vals.length?("$"+Math.round(d.vals.reduce((a,b)=>a+b,0)/d.vals.length/1000)+"K"):"N/A"
    })),
    topRoles: [...new Set(roster.map(r=>r.role))].slice(0,8),
    activeClientsCount: clients.length,
    recentWins: wonDeals.slice(0,3).map(d=>({client:d.clientName||d.company,value:d.value,stage:d.stage})),
    recentLosses: lostDeals.slice(0,3).map(d=>({client:d.clientName||d.company,value:d.value,notes:d.notes?.slice(0,80)})),
  });

  const PRESET_QUERIES = [
    "What's our best pitch for Utilities CIOs?",
    "Why do we lose deals? What are the patterns?",
    "What pricing wins BRIM roles?",
    "Which consultant profiles close deals fastest?",
    "What makes our top clients renew?",
    "What's our average deal cycle by vertical?",
    "How do we beat Accenture/Deloitte in proposals?",
    "What are the top 3 objections we hear?",
  ];

  // ── ASK ──────────────────────────────────────────────────────────────────
  const runQuery = async (q) => {
    const qText = q || query;
    if (!qText.trim()) return;
    setLoading(true); setAnswer(null);
    try {
      const resp = await fetch("/api/claude", { method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:2000,
          system:`You are the institutional knowledge AI for Ziksatech, a WBE-certified SAP consulting firm (Utilities/BRIM/SuccessFactors/S4HANA/MDG, DFW market). Answer from the firm's actual data. Be specific, practical, quantified.`,
          messages:[{role:"user",content:`Firm data:
${buildDigest()}

Question: ${qText}

Give a direct answer with: 1) Key insight from the data, 2) Supporting evidence, 3) Two actionable recommendations. Keep it punchy and specific to Ziksatech.`}]
        })
      });
      const data = await resp.json();
      const ans = { question: qText, answer: data.content?.[0]?.text||"No response.", ts: new Date().toLocaleTimeString() };
      setAnswer(ans);
      setHistory(prev => {
        const next = [ans, ...prev.filter(h=>h.question!==qText)].slice(0,10);
        localStorage.setItem("zt-ke-history", JSON.stringify(next));
        return next;
      });
    } catch(e) { setAnswer({question:qText, answer:"Error: "+e.message}); }
    setLoading(false);
  };

  // ── WIN/LOSS PATTERNS ─────────────────────────────────────────────────────
  const runPatterns = async () => {
    setPatternLoading(true); setPatterns(null);
    try {
      const resp = await fetch("/api/claude", { method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:2000,
          system:`You are a sales intelligence AI for Ziksatech, a SAP consulting firm.`,
          messages:[{role:"user",content:`Analyze this deal data and extract win/loss patterns:
${buildDigest()}

Respond ONLY with JSON:
{"winPatterns":[{"pattern":"...","evidence":"...","frequency":"HIGH|MEDIUM|LOW"},{"pattern":"...","evidence":"...","frequency":"..."},{"pattern":"...","evidence":"...","frequency":"..."}],"lossPatterns":[{"pattern":"...","reason":"...","howToFix":"..."},{"pattern":"...","reason":"...","howToFix":"..."},{"pattern":"...","reason":"...","howToFix":"..."}],"topVertical":"best vertical","worstVertical":"worst vertical","keyInsight":"one-sentence game-changer insight"}`}]
        })
      });
      const data = await resp.json();
      setPatterns(extractJSON(data.content?.[0]?.text||"{}"));
    } catch(e) { setPatterns({error:e.message}); }
    setPatternLoading(false);
  };

  // ── PLAYBOOK ──────────────────────────────────────────────────────────────
  const runPlaybook = async (vertical) => {
    setPlaybookLoading(true); setPlaybook(null);
    const vData = byVertical[vertical]||{won:0,lost:0,active:0,vals:[]};
    try {
      const resp = await fetch("/api/claude", { method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:2000,
          system:`You are a deal-closing AI for Ziksatech, a SAP consulting firm specializing in Utilities, BRIM, SuccessFactors, S4HANA. Generate a tactical playbook.`,
          messages:[{role:"user",content:`Generate a sales playbook for the ${vertical} vertical.
Vertical data: ${vData.won} wins, ${vData.lost} losses, ${vData.active} active deals, avg deal size ${vData.vals.length?("$"+Math.round(vData.vals.reduce((a,b)=>a+b,0)/vData.vals.length/1000)+"K"):"N/A"}.
Team capabilities: ${[...new Set(roster.map(r=>r.role))].slice(0,6).join(", ")}.

Respond ONLY with JSON:
{"targetBuyer":"title/role to target first","openingHook":"first sentence to say in cold outreach","keyPainPoints":["pain1","pain2","pain3"],"winningPitch":"2-sentence value prop specifically for this vertical","objections":[{"objection":"...","response":"..."},{"objection":"...","response":"..."}],"timeline":"typical deal cycle","mustHaveMeetings":["meeting1","meeting2","meeting3"],"closingTactic":"specific tactic to close this vertical"}`}]
        })
      });
      const data = await resp.json();
      setPlaybook({...extractJSON(data.content?.[0]?.text||"{}"), vertical});
    } catch(e) { setPlaybook({error:e.message}); }
    setPlaybookLoading(false);
  };

  // ── PRICING INTELLIGENCE ──────────────────────────────────────────────────
  const runPricing = async () => {
    setPricingLoading(true); setPricing(null);
    try {
      const resp = await fetch("/api/claude", { method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:2000,
          system:`You are a pricing intelligence AI for Ziksatech, a SAP consulting firm.`,
          messages:[{role:"user",content:`Analyze pricing intelligence based on this data:
${buildDigest()}
Consultant roles: ${[...new Set(roster.map(r=>r.role))].slice(0,10).join(", ")}
Current bill rates: ${roster.slice(0,6).map(r=>r.name+" $"+r.billRate+"/hr").join(", ")}

Respond ONLY with JSON:
{"rateByRole":[{"role":"...","marketLow":0,"marketMid":0,"marketHigh":0,"ziksatechCurrent":0,"recommendation":"..."},{"role":"...","marketLow":0,"marketMid":0,"marketHigh":0,"ziksatechCurrent":0,"recommendation":"..."},{"role":"...","marketLow":0,"marketMid":0,"marketHigh":0,"ziksatechCurrent":0,"recommendation":"..."}],"pricingStrategy":"overall pricing recommendation","discountGuideline":"when/how much to discount","premiumOpportunity":"where to charge more","totalLeaveOnTable":"estimated $ underpriced per month"}`}]
        })
      });
      const data = await resp.json();
      setPricing(extractJSON(data.content?.[0]?.text||"{}"));
    } catch(e) { setPricing({error:e.message}); }
    setPricingLoading(false);
  };

  const TABS = [
    {id:"ask",      label:"💬 Ask"},
    {id:"patterns", label:"📊 Win/Loss Patterns"},
    {id:"playbook", label:"📖 Playbooks"},
    {id:"pricing",  label:"💰 Pricing Intel"},
  ];

  return (
    <div>
      <PH title="🧩 Knowledge Engine" sub="Institutional brain · win/loss patterns · sales playbooks · pricing intelligence"/>

      {/* Stats */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:10,marginBottom:16}}>
        {[
          {l:"Total Deals",    v:crmDeals.length,                          c:"#38bdf8"},
          {l:"Win Rate",       v:winRate+"%",                              c:winRate>60?"#34d399":winRate>40?"#f59e0b":"#f87171"},
          {l:"Avg Won Size",   v:"$"+Math.round(avgDealSize/1000)+"K",    c:"#34d399"},
          {l:"Pipeline",       v:"$"+Math.round(pipelineVal/1000)+"K",    c:"#a78bfa"},
          {l:"Verticals",      v:verticals.length,                         c:"#f59e0b"},
        ].map(k=>(
          <div key={k.l} className="card" style={{padding:"10px 14px",textAlign:"center"}}>
            <div style={{fontSize:20,fontWeight:800,color:k.c,fontFamily:"'DM Mono',monospace"}}>{k.v}</div>
            <div style={{fontSize:10,color:"#475569",marginTop:2}}>{k.l}</div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div style={{display:"flex",gap:4,marginBottom:16,borderBottom:"1px solid #1a2d45",paddingBottom:4}}>
        {TABS.map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)}
            style={{padding:"7px 14px",borderRadius:"6px 6px 0 0",border:"none",fontSize:11,fontWeight:600,cursor:"pointer",
              background:tab===t.id?"#0c2340":"transparent",color:tab===t.id?"#38bdf8":"#475569",
              borderBottom:tab===t.id?"2px solid #0ea5e9":"2px solid transparent"}}>
            {t.label}
          </button>
        ))}
      </div>

      {/* ── ASK TAB ── */}
      {tab==="ask" && (
        <div>
          <div style={{display:"flex",gap:8,marginBottom:14}}>
            <input className="inp" style={{flex:1,fontSize:13}} placeholder="Ask anything about your deals, clients, pricing, patterns..."
              value={query} onChange={e=>setQuery(e.target.value)}
              onKeyDown={e=>e.key==="Enter"&&runQuery()}/>
            <button className="btn bp" style={{fontSize:12,padding:"8px 18px"}} onClick={()=>runQuery()} disabled={loading}>
              {loading?"⏳":"🔍 Ask"}
            </button>
          </div>

          {/* Preset queries */}
          <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:14}}>
            {PRESET_QUERIES.map(q=>(
              <button key={q} onClick={()=>{setQuery(q);runQuery(q);}}
                style={{padding:"5px 10px",borderRadius:6,border:"1px solid #1a2d45",background:"#060d1c",
                  color:"#475569",fontSize:10,cursor:"pointer"}}>
                {q}
              </button>
            ))}
          </div>

          {loading && <div className="card" style={{padding:24,textAlign:"center",color:"#475569",fontSize:12}}>🧠 Searching institutional knowledge...</div>}

          {answer && (
            <div className="card" style={{padding:"18px 20px"}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
                <div style={{fontSize:10,color:"#3d5a7a",textTransform:"uppercase",letterSpacing:.5}}>
                  Q: {answer.question}
                </div>
                <button className="btn bg" style={{fontSize:10,padding:"3px 10px"}}
                  onClick={()=>navigator.clipboard?.writeText(answer.answer)}>
                  📋 Copy
                </button>
              </div>
              <div style={{fontSize:13,color:"#e2e8f0",lineHeight:1.7,whiteSpace:"pre-wrap"}}>
                {answer.answer}
              </div>
            </div>
          )}

          {/* Ask History */}
          {history.length > 0 && !loading && (
            <div style={{marginTop:16}}>
              <div style={{fontSize:10,color:"#3d5a7a",marginBottom:8,textTransform:"uppercase",letterSpacing:.5,display:"flex",justifyContent:"space-between"}}>
                <span>📜 Recent Questions ({history.length})</span>
                <button onClick={()=>{setHistory([]);localStorage.removeItem("zt-ke-history");}} style={{background:"none",border:"none",color:"#334155",fontSize:10,cursor:"pointer"}}>Clear</button>
              </div>
              {history.slice(0,5).map((h,i)=>(
                <div key={i} style={{padding:"8px 12px",background:"#060d1c",borderRadius:6,border:"1px solid #1a2d45",marginBottom:6,cursor:"pointer"}}
                  onClick={()=>{setQuery(h.question);setAnswer(h);}}>
                  <div style={{fontSize:11,color:"#64748b",marginBottom:2}}>
                    {h.question.slice(0,60)}{h.question.length>60?"...":""} <span style={{color:"#334155",fontSize:9}}>{h.ts}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* ── WIN/LOSS PATTERNS TAB ── */}
      {tab==="patterns" && (
        <div>
          {!patterns && !patternLoading && (
            <div className="card" style={{padding:"32px",textAlign:"center"}}>
              <div style={{fontSize:32,marginBottom:10}}>📊</div>
              <div style={{fontSize:13,color:"#94a3b8",marginBottom:16}}>
                AI analyzes all {crmDeals.length} deals to extract the patterns that make Ziksatech win or lose
              </div>
              <button className="btn bp" style={{fontSize:13,padding:"10px 28px"}} onClick={runPatterns}>
                🔍 Analyze Win/Loss Patterns
              </button>
            </div>
          )}
          {patternLoading && <div className="card" style={{padding:24,textAlign:"center",color:"#475569",fontSize:12}}>🧠 Mining deal patterns...</div>}
          {patterns && !patterns.error && (
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
              {/* Win patterns */}
              <div className="card" style={{padding:"16px 18px"}}>
                <div style={{fontSize:12,fontWeight:700,color:"#34d399",marginBottom:12}}>✅ Why We WIN</div>
                {(patterns.winPatterns||[]).map((p,i)=>(
                  <div key={i} style={{marginBottom:10,padding:"10px 12px",background:"#021f14",border:"1px solid #15803d44",borderRadius:8}}>
                    <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                      <div style={{fontSize:11,fontWeight:700,color:"#4ade80"}}>{p.pattern}</div>
                      <span style={{fontSize:9,background:p.frequency==="HIGH"?"#15803d":"#1e3a5f",color:"#fff",borderRadius:4,padding:"1px 5px"}}>{p.frequency}</span>
                    </div>
                    <div style={{fontSize:10,color:"#64748b"}}>{p.evidence}</div>
                  </div>
                ))}
              </div>
              {/* Loss patterns */}
              <div className="card" style={{padding:"16px 18px"}}>
                <div style={{fontSize:12,fontWeight:700,color:"#f87171",marginBottom:12}}>❌ Why We LOSE</div>
                {(patterns.lossPatterns||[]).map((p,i)=>(
                  <div key={i} style={{marginBottom:10,padding:"10px 12px",background:"#1a0808",border:"1px solid #dc262644",borderRadius:8}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#f87171",marginBottom:3}}>{p.pattern}</div>
                    <div style={{fontSize:10,color:"#64748b",marginBottom:3}}>{p.reason}</div>
                    <div style={{fontSize:10,color:"#34d399"}}>→ Fix: {p.howToFix}</div>
                  </div>
                ))}
              </div>
              {/* Key insight */}
              {patterns.keyInsight && (
                <div style={{gridColumn:"1/-1",padding:"12px 16px",background:"#0c1a2e",border:"1px solid #0369a144",borderRadius:8}}>
                  <div style={{fontSize:10,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase",letterSpacing:.5}}>💡 Game-Changer Insight</div>
                  <div style={{fontSize:13,fontWeight:700,color:"#38bdf8"}}>{patterns.keyInsight}</div>
                </div>
              )}
              {/* Vertical breakdown */}
              <div style={{gridColumn:"1/-1"}} className="card">
                <div style={{fontSize:11,fontWeight:700,color:"#3d5a7a",marginBottom:10,padding:"12px 16px 0",textTransform:"uppercase",letterSpacing:.5}}>📊 By Vertical</div>
                <div style={{overflowX:"auto",padding:"0 16px 16px"}}>
                  <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
                    <thead>
                      <tr style={{borderBottom:"1px solid #1a2d45"}}>
                        {["Vertical","Won","Lost","Active","Win Rate","Avg Size"].map(h=><th key={h} className="th" style={{padding:"6px 10px",textAlign:"left"}}>{h}</th>)}
                      </tr>
                    </thead>
                    <tbody>
                      {verticals.map(v=>{
                        const d = byVertical[v];
                        const wr = d.won+d.lost>0?Math.round(d.won/(d.won+d.lost)*100):0;
                        const avg = d.vals.length?Math.round(d.vals.reduce((a,b)=>a+b,0)/d.vals.length/1000):0;
                        return (
                          <tr key={v} style={{borderBottom:"1px solid #0a1626"}}>
                            <td style={{padding:"7px 10px",color:"#e2e8f0",fontWeight:600}}>{v}</td>
                            <td style={{padding:"7px 10px",color:"#34d399"}}>{d.won}</td>
                            <td style={{padding:"7px 10px",color:"#f87171"}}>{d.lost}</td>
                            <td style={{padding:"7px 10px",color:"#38bdf8"}}>{d.active}</td>
                            <td style={{padding:"7px 10px",color:wr>60?"#34d399":wr>40?"#f59e0b":"#f87171",fontWeight:700}}>{wr}%</td>
                            <td style={{padding:"7px 10px",color:"#a78bfa"}}>{avg>0?"$"+avg+"K":"—"}</td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* ── PLAYBOOKS TAB ── */}
      {tab==="playbook" && (
        <div>
          <div style={{display:"flex",gap:8,marginBottom:14,flexWrap:"wrap"}}>
            {["Utilities","Tolling","Healthcare","Municipal","Energy","Manufacturing","Other"].map(v=>(
              <button key={v} onClick={()=>setSelVertical(v)}
                style={{padding:"6px 12px",borderRadius:6,border:`1px solid ${selVertical===v?"#0ea5e9":"#1a2d45"}`,
                  background:selVertical===v?"#0c2340":"transparent",color:selVertical===v?"#38bdf8":"#475569",
                  fontSize:11,fontWeight:600,cursor:"pointer"}}>
                {v}
              </button>
            ))}
            <button className="btn bp" style={{fontSize:11,padding:"6px 14px"}} disabled={playbookLoading}
              onClick={()=>runPlaybook(selVertical)}>
              {playbookLoading?"⏳ Building...":"📖 Generate Playbook"}
            </button>
          </div>

          {!playbook && !playbookLoading && (
            <div className="card" style={{padding:"28px",textAlign:"center",color:"#475569",fontSize:12}}>
              Select a vertical and click Generate Playbook to get a tactical close guide
            </div>
          )}

          {playbook && !playbook.error && (
            <div>
              <div style={{fontSize:14,fontWeight:700,color:"#e2e8f0",marginBottom:14}}>
                📖 {playbook.vertical} Playbook
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                {[
                  {icon:"🎯",label:"Target Buyer",   val:playbook.targetBuyer,    bg:"#0c1a2e",col:"#38bdf8"},
                  {icon:"🗣",label:"Opening Hook",   val:playbook.openingHook,    bg:"#021f14",col:"#34d399"},
                  {icon:"💬",label:"Winning Pitch",  val:playbook.winningPitch,   bg:"#1a1000",col:"#f59e0b"},
                  {icon:"📅",label:"Deal Timeline",  val:playbook.timeline,       bg:"#0d0b1a",col:"#a78bfa"},
                  {icon:"🏆",label:"Closing Tactic", val:playbook.closingTactic,  bg:"#021f14",col:"#34d399"},
                ].map(s=>(
                  <div key={s.label} style={{padding:"12px 14px",background:s.bg,borderRadius:8,border:`1px solid ${s.col}22`}}>
                    <div style={{fontSize:9,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase",letterSpacing:.5}}>{s.icon} {s.label}</div>
                    <div style={{fontSize:11,color:s.col,lineHeight:1.5}}>{s.val||"—"}</div>
                  </div>
                ))}
                {/* Pain points */}
                <div style={{padding:"12px 14px",background:"#1a0808",borderRadius:8,border:"1px solid #dc262644"}}>
                  <div style={{fontSize:9,color:"#3d5a7a",marginBottom:6,textTransform:"uppercase",letterSpacing:.5}}>🔥 Key Pain Points</div>
                  {(playbook.keyPainPoints||[]).map((p,i)=>(
                    <div key={i} style={{fontSize:11,color:"#f87171",marginBottom:4}}>• {p}</div>
                  ))}
                </div>
              </div>
              {/* Objections */}
              {(playbook.objections||[]).length>0 && (
                <div className="card" style={{marginTop:12,padding:"14px 16px"}}>
                  <div style={{fontSize:10,fontWeight:700,color:"#3d5a7a",marginBottom:10,textTransform:"uppercase",letterSpacing:.5}}>🛡 Objection Handling</div>
                  {playbook.objections.map((o,i)=>(
                    <div key={i} style={{marginBottom:10,display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
                      <div style={{padding:"8px 10px",background:"#1a0808",borderRadius:6,fontSize:10,color:"#f87171"}}>
                        <strong>Objection:</strong> {o.objection}
                      </div>
                      <div style={{padding:"8px 10px",background:"#021f14",borderRadius:6,fontSize:10,color:"#34d399"}}>
                        <strong>Response:</strong> {o.response}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* ── PRICING INTELLIGENCE TAB ── */}
      {tab==="pricing" && (
        <div>
          {!pricing && !pricingLoading && (
            <div className="card" style={{padding:"32px",textAlign:"center"}}>
              <div style={{fontSize:32,marginBottom:10}}>💰</div>
              <div style={{fontSize:13,color:"#94a3b8",marginBottom:16}}>
                AI benchmarks your rates against DFW SAP consulting market rates and identifies where you're leaving money on the table
              </div>
              <button className="btn bp" style={{fontSize:13,padding:"10px 28px"}} onClick={runPricing}>
                💰 Run Pricing Analysis
              </button>
            </div>
          )}
          {pricingLoading && <div className="card" style={{padding:24,textAlign:"center",color:"#475569",fontSize:12}}>💰 Benchmarking rates...</div>}
          {pricing && !pricing.error && (
            <div>
              {/* Summary */}
              {pricing.totalLeaveOnTable && (
                <div style={{padding:"12px 16px",background:"#1a0808",border:"1px solid #f8717144",borderRadius:10,marginBottom:14}}>
                  <div style={{fontSize:12,fontWeight:700,color:"#f87171",marginBottom:2}}>💸 Estimated Leave on Table: {pricing.totalLeaveOnTable}/month</div>
                  <div style={{fontSize:11,color:"#94a3b8"}}>{pricing.pricingStrategy}</div>
                </div>
              )}
              {/* Rate table */}
              <div className="card" style={{padding:"14px 16px",marginBottom:12,overflowX:"auto"}}>
                <div style={{fontSize:11,fontWeight:700,color:"#3d5a7a",marginBottom:10,textTransform:"uppercase",letterSpacing:.5}}>📊 Rate Benchmarks by Role</div>
                <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
                  <thead>
                    <tr style={{borderBottom:"1px solid #1a2d45"}}>
                      {["Role","Market Low","Market Mid","Market High","Your Rate","Recommendation"].map(h=>(
                        <th key={h} className="th" style={{padding:"6px 10px",textAlign:"left"}}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {(pricing.rateByRole||[]).map((r,i)=>{
                      const isBehind = r.ziksatechCurrent < r.marketMid;
                      return (
                        <tr key={i} style={{borderBottom:"1px solid #0a1626"}}>
                          <td style={{padding:"7px 10px",color:"#e2e8f0",fontWeight:600}}>{r.role}</td>
                          <td style={{padding:"7px 10px",color:"#3d5a7a"}}>${r.marketLow}</td>
                          <td style={{padding:"7px 10px",color:"#94a3b8"}}>${r.marketMid}</td>
                          <td style={{padding:"7px 10px",color:"#34d399"}}>${r.marketHigh}</td>
                          <td style={{padding:"7px 10px",color:isBehind?"#f87171":"#34d399",fontWeight:700}}>${r.ziksatechCurrent}</td>
                          <td style={{padding:"7px 10px",color:"#38bdf8",fontSize:10}}>{r.recommendation}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div style={{padding:"10px 14px",background:"#021f14",border:"1px solid #15803d44",borderRadius:8}}>
                  <div style={{fontSize:9,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase"}}>💎 Premium Opportunity</div>
                  <div style={{fontSize:11,color:"#34d399"}}>{pricing.premiumOpportunity}</div>
                </div>
                <div style={{padding:"10px 14px",background:"#1a1000",border:"1px solid #d9770644",borderRadius:8}}>
                  <div style={{fontSize:9,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase"}}>🔻 Discount Guideline</div>
                  <div style={{fontSize:11,color:"#f59e0b"}}>{pricing.discountGuideline}</div>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}


function ScenarioSimulator({ roster, clients, finInvoices, finPayments, crmDeals, finExpenses, authProfile }) {
  const fmt  = n => "$"+Math.round(n).toLocaleString();
  const fmtK = n => n>=1000000?"$"+Math.round(n/1000000*10)/10+"M":n>=1000?"$"+Math.round(n/1000)+"K":fmt(n);
  const pct  = n => (n>=0?"+":"")+Math.round(n)+"%";

  const BLANK_SCENARIO = { name:"Custom", newHires:0, avgBillRate:150, dealCloseProb:0, rateIncrease:0, clientChurn:0, benchReduction:0 };

  const QUICK_SCENARIOS = [
    { name:"🚀 Aggressive Growth",  newHires:5, avgBillRate:165, dealCloseProb:60, rateIncrease:10, clientChurn:0,  benchReduction:50 },
    { name:"⚖️ Balanced Expansion", newHires:2, avgBillRate:155, dealCloseProb:40, rateIncrease:5,  clientChurn:0,  benchReduction:25 },
    { name:"🛡 Conservative",        newHires:0, avgBillRate:150, dealCloseProb:25, rateIncrease:3,  clientChurn:0,  benchReduction:0  },
    { name:"💰 Rate Optimisation",   newHires:0, avgBillRate:150, dealCloseProb:0,  rateIncrease:15, clientChurn:0,  benchReduction:0  },
    { name:"⚠️ Worst Case",         newHires:0, avgBillRate:150, dealCloseProb:0,  rateIncrease:0,  clientChurn:20, benchReduction:0  },
    { name:"🏆 Best Case",           newHires:8, avgBillRate:175, dealCloseProb:80, rateIncrease:15, clientChurn:0,  benchReduction:100},
  ];

  const [scenario,   setScenario]   = useState(BLANK_SCENARIO);
  const [loading,    setLoading]    = useState(false);
  const [narrative,  setNarrative]  = useState(null);
  const [savedScenarios, setSavedScenarios] = useState([]);
  const [comparing,  setComparing]  = useState(null); // second scenario for side-by-side

  // ── Base metrics ─────────────────────────────────────────────────────────
  const baseRevenue = roster.reduce((s,r) => {
    const hrs = (r.util||0) * 160 * 12;
    return s + hrs * (r.billRate||0);
  }, 0);
  const baseCost    = roster.reduce((s,r) => s + getEmployeeCost(r), 0);
  const baseProfit  = baseRevenue - baseCost;
  const baseMargin  = baseRevenue > 0 ? (baseRevenue - baseCost) / baseRevenue * 100 : 0;
  const pipelineTotal = crmDeals.filter(d=>!["closed-won","closed_won","closed-lost","closed_lost"].includes(d.stage)).reduce((s,d)=>s+(d.value||0),0);

  // ── Scenario calculations ────────────────────────────────────────────────
  const calcScenario = (s) => {
    const newHireRevenue   = s.newHires * s.avgBillRate * 1920 * 0.85;
    const newHireCost      = s.newHires * 135000;
    const pipelineRevenue  = pipelineTotal * (s.dealCloseProb / 100);
    const rateUplift       = roster.reduce((sum,r) => sum + (r.billRate||0) * (r.util||0) * 1920 * (s.rateIncrease/100), 0);
    const churnLoss        = (s.clientChurn / 100) * baseRevenue;
    const benchSaving      = roster.filter(r=>(r.util||0)<0.3).reduce((sum,r) => sum + getEmployeeCost(r) * (s.benchReduction/100), 0);
    const projRevenue = baseRevenue + newHireRevenue + pipelineRevenue + rateUplift - churnLoss;
    const projCost    = baseCost + newHireCost - benchSaving;
    const projProfit  = projRevenue - projCost;
    const projMargin  = projRevenue > 0 ? (projRevenue - projCost) / projRevenue * 100 : 0;
    return { projRevenue, projCost, projProfit, projMargin,
      revDelta: projRevenue - baseRevenue, profitDelta: projProfit - baseProfit,
      marginDelta: projMargin - baseMargin,
      breakdown: { newHireRevenue, newHireCost, pipelineRevenue, rateUplift, churnLoss, benchSaving }
    };
  };

  const result   = calcScenario(scenario);
  const cmpResult = comparing ? calcScenario(comparing) : null;

  const runNarrative = async () => {
    setLoading(true); setNarrative(null);
    const r = result;
    try {
      const resp = await fetch("/api/claude", { method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:2000,
          system:"You are a CFO-level scenario analysis AI for Ziksatech, a SAP consulting firm.",
          messages:[{role:"user",content:
`Scenario: "${scenario.name}"
Base:      Revenue ${fmtK(baseRevenue)} | Profit ${fmtK(baseProfit)} | Margin ${Math.round(baseMargin)}%
Projected: Revenue ${fmtK(r.projRevenue)} | Profit ${fmtK(r.projProfit)} | Margin ${Math.round(r.projMargin)}%
Delta:     Revenue ${fmtK(r.revDelta)} | Profit ${fmtK(r.profitDelta)}
Inputs: ${scenario.newHires} new hires @$${scenario.avgBillRate}/hr, ${scenario.dealCloseProb}% pipeline close ($${Math.round(pipelineTotal/1000)}K pipeline), ${scenario.rateIncrease}% rate increase, ${scenario.clientChurn}% client churn, ${scenario.benchReduction}% bench cost reduction

In 4 sentences: (1) overall CFO verdict on this scenario, (2) biggest upside driver, (3) biggest risk, (4) one specific recommendation to maximise ROI. Be specific to a SAP consulting firm.`
          }]
        })
      });
      const data = await resp.json();
      setNarrative(data.content?.[0]?.text || "Analysis unavailable.");
    } catch(e) { setNarrative("Error: "+e.message); }
    setLoading(false);
  };

  const SLIDER_CONFIG = [
    { key:"newHires",       label:"New Hires",               min:0, max:20, step:1, suffix:" FTEs" },
    { key:"avgBillRate",    label:"Avg Bill Rate ($/hr)",     min:100, max:300, step:5, suffix:"/hr" },
    { key:"dealCloseProb",  label:"Pipeline Close Rate",      min:0, max:100, step:5, suffix:"%" },
    { key:"rateIncrease",   label:"Rate Increase on Existing",min:0, max:30,  step:1, suffix:"%" },
    { key:"clientChurn",    label:"Client Churn Risk",        min:0, max:50,  step:1, suffix:"%" },
    { key:"benchReduction", label:"Bench Cost Reduction",     min:0, max:100, step:5, suffix:"%" },
  ];

  const MetricCard = ({label, base, proj, suffix=""}) => {
    const delta = proj - base;
    const col = delta >= 0 ? "#34d399" : "#f87171";
    return (
      <div className="card" style={{padding:"12px 14px",textAlign:"center"}}>
        <div style={{fontSize:9,color:"#475569",textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>{label}</div>
        <div style={{fontSize:9,color:"#3d5a7a",marginBottom:2}}>Base: <span style={{color:"#64748b",fontFamily:"monospace"}}>{typeof base==="number"&&base>1000?fmtK(base):Math.round(base)+suffix}</span></div>
        <div style={{fontSize:18,fontWeight:800,color:col,fontFamily:"'DM Mono',monospace"}}>{typeof proj==="number"&&proj>1000?fmtK(proj):Math.round(proj)+suffix}</div>
        <div style={{fontSize:10,fontWeight:700,color:col}}>{delta>=0?"+":""}{typeof delta==="number"&&Math.abs(delta)>1000?fmtK(delta):Math.round(delta)+suffix}</div>
      </div>
    );
  };

  return (
    <div>
      <PH title="📊 Scenario Simulator" sub="What-if modelling · pre-built CEO scenarios · side-by-side comparison · AI CFO assessment"/>

      {/* Quick scenario buttons */}
      <div style={{marginBottom:16}}>
        <div style={{fontSize:10,color:"#3d5a7a",marginBottom:8,textTransform:"uppercase",letterSpacing:.5}}>⚡ Quick Scenarios</div>
        <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
          {QUICK_SCENARIOS.map(qs=>(
            <button key={qs.name} onClick={()=>{setScenario({...qs});setNarrative(null);setComparing(null);}}
              style={{padding:"6px 12px",borderRadius:6,border:`1px solid ${scenario.name===qs.name?"#0ea5e9":"#1a2d45"}`,
                background:scenario.name===qs.name?"#0c2340":"#060d1c",
                color:scenario.name===qs.name?"#38bdf8":"#475569",fontSize:10,fontWeight:600,cursor:"pointer"}}>
              {qs.name}
            </button>
          ))}
        </div>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
        {/* ── LEFT: Sliders ── */}
        <div>
          <div className="card" style={{padding:"16px 18px",marginBottom:12}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
              <div style={{fontSize:11,fontWeight:700,color:"#e2e8f0"}}>
                {scenario.name || "Custom Scenario"}
              </div>
              <button className="btn bg" style={{fontSize:10}}
                onClick={()=>setScenario({...BLANK_SCENARIO})}>Reset</button>
            </div>
            {SLIDER_CONFIG.map(cfg=>(
              <div key={cfg.key} style={{marginBottom:14}}>
                <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                  <span style={{fontSize:10,color:"#64748b"}}>{cfg.label}</span>
                  <span style={{fontSize:11,fontWeight:700,color:"#38bdf8",fontFamily:"monospace"}}>
                    {scenario[cfg.key]}{cfg.suffix}
                  </span>
                </div>
                <input type="range" min={cfg.min} max={cfg.max} step={cfg.step}
                  value={scenario[cfg.key]}
                  onChange={e=>{ setScenario(s=>({...s,[cfg.key]:+e.target.value,name:"Custom"})); setNarrative(null); }}
                  style={{width:"100%",accentColor:"#0ea5e9"}}/>
                <div style={{display:"flex",justifyContent:"space-between",fontSize:9,color:"#334155"}}>
                  <span>{cfg.min}{cfg.suffix}</span><span>{cfg.max}{cfg.suffix}</span>
                </div>
              </div>
            ))}
          </div>

          {/* Compare with quick scenario */}
          <div className="card" style={{padding:"12px 14px",marginBottom:12}}>
            <div style={{fontSize:10,color:"#3d5a7a",marginBottom:8,textTransform:"uppercase",letterSpacing:.5}}>⚖️ Compare Against</div>
            <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
              {QUICK_SCENARIOS.map(qs=>(
                <button key={qs.name} onClick={()=>setComparing(comparing?.name===qs.name?null:qs)}
                  style={{padding:"4px 8px",borderRadius:5,border:`1px solid ${comparing?.name===qs.name?"#7c3aed":"#1a2d45"}`,
                    background:comparing?.name===qs.name?"#0d0b1a":"transparent",
                    color:comparing?.name===qs.name?"#a78bfa":"#475569",fontSize:9,cursor:"pointer"}}>
                  {qs.name}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* ── RIGHT: Output ── */}
        <div>
          {/* Main metrics */}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:12}}>
            <MetricCard label="Annual Revenue" base={baseRevenue} proj={result.projRevenue}/>
            <MetricCard label="Annual Profit"  base={baseProfit}  proj={result.projProfit}/>
            <MetricCard label="Profit Margin"  base={baseMargin}  proj={result.projMargin} suffix="%"/>
            <MetricCard label="Monthly Revenue" base={baseRevenue/12} proj={result.projRevenue/12}/>
          </div>

          {/* Side-by-side comparison */}
          {cmpResult && (
            <div className="card" style={{padding:"12px 14px",marginBottom:12,border:"1px solid #7c3aed44"}}>
              <div style={{fontSize:10,fontWeight:700,color:"#a78bfa",marginBottom:8}}>⚖️ Side-by-Side: {scenario.name} vs {comparing.name}</div>
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
                <thead>
                  <tr style={{borderBottom:"1px solid #1a2d45"}}>
                    {["Metric","Base","Current","Compare"].map(h=>(
                      <th key={h} className="th" style={{padding:"5px 8px",textAlign:"right",fontSize:9}}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {[
                    ["Revenue",  baseRevenue,  result.projRevenue, cmpResult.projRevenue],
                    ["Profit",   baseProfit,   result.projProfit,  cmpResult.projProfit],
                    ["Margin",   baseMargin,   result.projMargin,  cmpResult.projMargin],
                  ].map(([l,b,a,cmp])=>{
                    const aDelta = a-b; const cmpDelta = cmp-b;
                    const better = aDelta >= cmpDelta;
                    return (
                      <tr key={l} style={{borderBottom:"1px solid #0a1626"}}>
                        <td style={{padding:"5px 8px",color:"#94a3b8"}}>{l}</td>
                        <td style={{padding:"5px 8px",textAlign:"right",color:"#475569",fontFamily:"monospace"}}>{l==="Margin"?Math.round(b)+"%":fmtK(b)}</td>
                        <td style={{padding:"5px 8px",textAlign:"right",color:aDelta>=0?"#34d399":"#f87171",fontWeight:700,fontFamily:"monospace"}}>
                          {l==="Margin"?Math.round(a)+"%":fmtK(a)} {better?"✓":""}
                        </td>
                        <td style={{padding:"5px 8px",textAlign:"right",color:cmpDelta>=0?"#34d399":"#f87171",fontFamily:"monospace"}}>
                          {l==="Margin"?Math.round(cmp)+"%":fmtK(cmp)} {!better?"✓":""}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}

          {/* Impact breakdown */}
          <div className="card" style={{padding:"12px 14px",marginBottom:12}}>
            <div style={{fontSize:10,fontWeight:700,color:"#3d5a7a",marginBottom:8,textTransform:"uppercase",letterSpacing:.5}}>📊 Impact Breakdown</div>
            {[
              ["+New hire revenue",  result.breakdown.newHireRevenue,  "#34d399"],
              ["+Pipeline close",    result.breakdown.pipelineRevenue, "#34d399"],
              ["+Rate uplift",       result.breakdown.rateUplift,      "#34d399"],
              ["+Bench saving",      result.breakdown.benchSaving,     "#a78bfa"],
              ["−New hire cost",    -result.breakdown.newHireCost,     "#f87171"],
              ["−Client churn",     -result.breakdown.churnLoss,       "#f87171"],
            ].filter(([,v])=>Math.abs(v)>0).map(([l,v,col])=>(
              <div key={l} style={{display:"flex",justifyContent:"space-between",padding:"5px 0",borderBottom:"1px solid #0a1626"}}>
                <span style={{fontSize:11,color:"#64748b"}}>{l}</span>
                <span style={{fontSize:11,fontFamily:"monospace",color:col,fontWeight:700}}>{v>=0?"+":""}{fmtK(v)}</span>
              </div>
            ))}
          </div>

          {/* AI CFO Assessment */}
          {narrative ? (
            <div className="card" style={{padding:"14px 16px",border:"1px solid #0369a144"}}>
              <div style={{fontSize:11,fontWeight:700,color:"#38bdf8",marginBottom:8}}>🤖 CFO Assessment — {scenario.name}</div>
              <p style={{fontSize:12,color:"#94a3b8",lineHeight:1.7,margin:0}}>{narrative}</p>
              <button className="btn bg" style={{fontSize:10,marginTop:10}} onClick={()=>setNarrative(null)}>↺ Re-run</button>
            </div>
          ) : (
            <button className="btn bp" style={{width:"100%",justifyContent:"center",fontSize:12}} onClick={runNarrative} disabled={loading}>
              {loading?"⏳ Analysing scenario...":"🤖 Get AI CFO Assessment"}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}


function PerformanceCoach({ roster, clients, crmDeals, proposals, tsSubmissions,
  finInvoices, interviews, submissions, authProfile }) {

  const [role,      setRole]      = useState("sales");
  const [loading,   setLoading]   = useState(false);
  const [insight,   setInsight]   = useState(null);
  const [selMember, setSelMember] = useState("");
  const [view,      setView]      = useState("coach"); // coach | leaderboard
  const [lbLoading, setLbLoading] = useState(false);
  const [leaderboard, setLeaderboard] = useState(null);

  const ROLES = [
    { id:"sales",     label:"🎯 Sales",         icon:"🎯" },
    { id:"recruiter", label:"👥 Recruiter",      icon:"👥" },
    { id:"delivery",  label:"🚀 Delivery Mgr",  icon:"🚀" },
    { id:"exec",      label:"📊 Exec Overview",  icon:"📊" },
  ];

  // ── Build performance data per role ─────────────────────────────────────
  const salesData = () => {
    const deals = crmDeals || [];
    const won   = deals.filter(d=>d.stage==="won");
    const lost  = deals.filter(d=>d.stage==="lost");
    const open  = deals.filter(d=>!["won","lost"].includes(d.stage));
    const winRate = deals.length ? Math.round(won.length/Math.max(won.length+lost.length,1)*100) : 0;
    const avgDeal = won.length ? Math.round(won.reduce((s,d)=>s+(+d.value||0),0)/won.length) : 0;
    // Stage velocity — avg days per stage
    const stageVel = {};
    deals.forEach(d => {
      if (d.stageHistory) {
        d.stageHistory.forEach((s,i) => {
          if (i>0) {
            const days = Math.round((new Date(s.date)-new Date(d.stageHistory[i-1].date))/(86400000));
            stageVel[s.stage] = stageVel[s.stage] || [];
            stageVel[s.stage].push(days);
          }
        });
      }
    });
    // Lost reasons
    const lostReasons = {};
    lost.forEach(d=>{
      const r = d.lostReason||"Unknown";
      lostReasons[r] = (lostReasons[r]||0)+1;
    });
    return { won:won.length, lost:lost.length, open:open.length, winRate, avgDeal,
      totalPipeline: open.reduce((s,d)=>s+(+d.value||0),0),
      lostReasons, recentWon: won.slice(-3), recentLost: lost.slice(-3) };
  };

  const recruiterData = () => {
    const subs  = submissions || [];
    const ints  = interviews  || [];
    const offs  = [];
    const placed = subs.filter(s=>s.status==="placed");
    const submitToInt = subs.length ? Math.round(ints.length/Math.max(subs.length,1)*100) : 0;
    const intToOffer  = ints.length ? Math.round(offs.length/Math.max(ints.length,1)*100) : 0;
    const avgDaysToPlace = placed.length ? 30 : 0; // approximate
    return { submitted:subs.length, interviewed:ints.length, placed:placed.length,
      submitToInt, intToOffer, avgDaysToPlace,
      topClients: [...new Set(placed.map(s=>s.clientId))].slice(0,3),
      pipeline: subs.filter(s=>!["placed","rejected"].includes(s.status)).length };
  };

  const deliveryData = () => {
    const sheets  = tsSubmissions || [];
    const invoices= finInvoices   || [];
    const approved = sheets.filter(s=>["approved","client_approved","invoiced"].includes(s.status));
    const rejected = sheets.filter(s=>s.status==="rejected");
    const onTime   = invoices.filter(i=>i.status==="paid").length;
    const overdue  = invoices.filter(i=>i.status==="overdue").length;
    const utilRate = roster?.length ?
      Math.round(roster.filter(r=>r.status==="active").length/Math.max(roster.length,1)*100) : 0;
    return { totalSheets:sheets.length, approved:approved.length, rejected:rejected.length,
      rejectionRate: sheets.length ? Math.round(rejected.length/sheets.length*100) : 0,
      invoicesPaid:onTime, invoicesOverdue:overdue, utilRate,
      activeConsultants: roster?.filter(r=>r.status==="active").length||0 };
  };

  const execData = () => {
    const s = salesData(); const r = recruiterData(); const d = deliveryData();
    const rev = (finInvoices||[]).filter(i=>i.status==="paid").reduce((sum,i)=>sum+(+i.amount||0),0);
    const pipeline = s.totalPipeline;
    return { ...s, ...r, ...d, rev, pipeline };
  };

  // ── AI Analysis ──────────────────────────────────────────────────────────
  const analyze = async () => {
    setLoading(true); setInsight(null);
    const data = role==="sales"?salesData():role==="recruiter"?recruiterData():
      role==="delivery"?deliveryData():execData();

    const prompt = `You are a performance coach for a staffing & IT consulting firm.
Analyze this ${role} performance data and give brutally honest, specific coaching insights.

Role: ${role.toUpperCase()}
Data: ${JSON.stringify(data, null, 2)}

Respond in JSON only (no markdown):
{
  "headline": "one punchy insight sentence",
  "score": 1-10,
  "scoreLabel": "e.g. Strong / Needs Work / Critical",
  "strengths": ["specific strength 1", "specific strength 2"],
  "gaps": ["specific gap 1", "specific gap 2", "specific gap 3"],
  "patterns": ["behavioral pattern observed 1", "behavioral pattern 2"],
  "topAction": "THE single most impactful thing to do this week",
  "quickWins": ["quick win 1", "quick win 2", "quick win 3"],
  "benchmark": "How this compares to top-performing consulting firms",
  "forecast": "What happens in 30 days if nothing changes"
}`;

    try {
      const res = await fetch("/api/claude", {
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          model:"claude-sonnet-4-20250514", max_tokens:2000,
          messages:[{role:"user",content:prompt}]
        })
      });
      const d = await res.json();
      const text = d.content?.[0]?.text||"{}";
      const clean = text.replace(/```json|```/g,"").trim();
      setInsight(extractJSON(clean));
    } catch(e) { setInsight({headline:"Analysis failed — check connection",score:0,strengths:[],gaps:[],patterns:[],topAction:"",quickWins:[],benchmark:"",forecast:""}); }
    setLoading(false);
  };

  const runLeaderboard = async () => {
    setLbLoading(true); setLeaderboard(null);
    // Build per-consultant performance metrics
    const consultants = (roster||[]).filter(r=>r.type==="FTE"||r.type==="Contractor").slice(0,12);
    const metrics = consultants.map(r => {
      const util = Math.round((r.util||0)*100);
      const revenue = Math.round((r.billRate||0)*(r.util||0)*1920);
      const cost = getEmployeeCost(r);
      const margin = revenue>0?Math.round((revenue-cost)/revenue*100):0;
      // Recent timesheet submissions
      const tsCount = (tsSubmissions||[]).filter(s=>s.consultantId===r.id||s.memberName===r.name).length;
      return { name:r.name, role:r.role, type:r.type, util, revenue, cost, margin, billRate:r.billRate||0, tsCount };
    }).sort((a,b)=>b.revenue-a.revenue);

    const totalRevenue = metrics.reduce((s,m)=>s+m.revenue,0);
    const avgUtil = metrics.length?Math.round(metrics.reduce((s,m)=>s+m.util,0)/metrics.length):0;
    const avgMargin = metrics.length?Math.round(metrics.reduce((s,m)=>s+m.margin,0)/metrics.length):0;
    
    try {
      const resp = await fetch("/api/claude", { method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:2000,
          system:"You are a performance analytics AI for Ziksatech, a SAP consulting firm. Analyze team performance and identify top performers, at-risk consultants, and coaching opportunities.",
          messages:[{role:"user",content:`You are analyzing the Ziksatech team for the ${role} role.

Team performance data:
${JSON.stringify(metrics,null,2)}

Team averages: Util ${avgUtil}%, Margin ${avgMargin}%, Total annual revenue $${Math.round(totalRevenue/1000)}K

TOP PERFORMERS (sorted by utilisation):
${[...roster].sort((a,b)=>(b.util||0)-(a.util||0)).slice(0,3).map((r,i)=>
  `${i+1}. ${r.name} (${r.role}) — ${Math.round((r.util||0)*100)}% util, $${r.billRate}/hr, ${r.type}`
).join("\n")}

BENCH / LOW PERFORMERS:
${[...roster].filter(r=>(r.util||0)<0.3).map(r=>
  `${r.name} (${r.role}) — ${Math.round((r.util||0)*100)}% util`
).join("\n") || "None currently on bench"}

Respond ONLY with JSON (no markdown):
{"headline":"one punchy insight sentence","score":1-10,"scoreLabel":"Strong|Good|Needs Work|Critical","strengths":["specific strength 1","specific strength 2"],"gaps":["gap 1","gap 2","gap 3"],"patterns":["behavioral pattern 1","behavioral pattern 2"],"topAction":"THE single most impactful action this week","quickWins":["quick win 1","quick win 2","quick win 3"],"benchmark":"How Ziksatech team compares to top SAP consulting firms (be specific: mention typical utilisation rates, bill rates, margins)","forecast":"What happens in 30 days if current patterns continue (be specific with $)","topPerformerBehaviors":["what top performers do that others don't 1","behavior 2","behavior 3"],"coachingPlan":{"week1":"specific action","week2":"specific action","week3":"specific action","week4":"specific action"}}`}]
        })
      });
      const data = await resp.json();
      const parsed = extractJSON(data.content?.[0]?.text||"{}");
      setLeaderboard({ ...parsed, metrics, totalRevenue, avgUtil, avgMargin });
    } catch(e) { setLeaderboard({error:e.message}); }
    setLbLoading(false);
  };


  const data = role==="sales"?salesData():role==="recruiter"?recruiterData():
    role==="delivery"?deliveryData():execData();

  const scoreColor = s => s>=8?"#34d399":s>=6?"#f59e0b":s>=4?"#fb923c":"#f87171";

  return (
    <div>
      <PH title="🏆 Performance Coach" sub="Behavioral analysis · pattern detection · coaching for sales, recruiters & delivery"/>

      {/* Role Selector */}
      {/* View toggle */}
      <div style={{display:"flex",gap:6,marginBottom:14}}>
        {[["coach","🎯 Coach Mode"],["leaderboard","🏆 Leaderboard"]].map(([v,l])=>(
          <button key={v} onClick={()=>setView(v)}
            style={{padding:"7px 16px",borderRadius:6,border:`1px solid ${view===v?"#0ea5e9":"#1a2d45"}`,
              background:view===v?"#0c2340":"transparent",color:view===v?"#38bdf8":"#475569",
              fontSize:11,fontWeight:600,cursor:"pointer"}}>
            {l}
          </button>
        ))}
      </div>

      {view==="coach" && <div style={{display:"flex",gap:8,marginBottom:20,flexWrap:"wrap"}}>
        {ROLES.map(r=>(
          <button key={r.id} className={role===r.id?"btn bp":"btn bg"}
            style={{fontSize:12,padding:"8px 18px",fontWeight:role===r.id?700:400}}
            onClick={()=>{setRole(r.id);setInsight(null);}}>
            {r.label}
          </button>
        ))}
        <button className="btn bp" style={{fontSize:12,padding:"8px 18px",marginLeft:"auto",fontWeight:700}}
          onClick={analyze} disabled={loading}>
          {loading?"⏳ Analyzing...":"🔍 Run Analysis"}
        </button>
      </div>}

      {/* Live KPI Snapshot */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
        {role==="sales" && [
          ["Win Rate",       `${data.winRate}%`,        "#34d399"],
          ["Deals Won",      data.won,                  "#38bdf8"],
          ["Open Pipeline",  `$${(data.totalPipeline/1000).toFixed(0)}K`, "#a78bfa"],
          ["Avg Deal Size",  `$${(data.avgDeal/1000).toFixed(0)}K`,       "#f59e0b"],
        ].map(([l,v,col])=>(
          <div key={l} className="card" style={{padding:"12px 14px",textAlign:"center"}}>
            <div style={{fontSize:9,color:"#3d5a7a",textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>{l}</div>
            <div style={{fontSize:22,fontWeight:800,color:col}}>{v}</div>
          </div>
        ))}
        {role==="recruiter" && [
          ["Submitted",    data.submitted,          "#38bdf8"],
          ["Interviewed",  data.interviewed,        "#a78bfa"],
          ["Placed",       data.placed,             "#34d399"],
          ["Sub→Int Rate", `${data.submitToInt}%`,  "#f59e0b"],
        ].map(([l,v,col])=>(
          <div key={l} className="card" style={{padding:"12px 14px",textAlign:"center"}}>
            <div style={{fontSize:9,color:"#3d5a7a",textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>{l}</div>
            <div style={{fontSize:22,fontWeight:800,color:col}}>{v}</div>
          </div>
        ))}
        {role==="delivery" && [
          ["Active Consultants", data.activeConsultants,  "#38bdf8"],
          ["Utilization",        `${data.utilRate}%`,     data.utilRate>=80?"#34d399":data.utilRate>=60?"#f59e0b":"#f87171"],
          ["Rejection Rate",     `${data.rejectionRate}%`,data.rejectionRate<5?"#34d399":"#f87171"],
          ["Overdue Invoices",   data.invoicesOverdue,    data.invoicesOverdue===0?"#34d399":"#f87171"],
        ].map(([l,v,col])=>(
          <div key={l} className="card" style={{padding:"12px 14px",textAlign:"center"}}>
            <div style={{fontSize:9,color:"#3d5a7a",textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>{l}</div>
            <div style={{fontSize:22,fontWeight:800,color:col}}>{v}</div>
          </div>
        ))}
        {role==="exec" && [
          ["Total Revenue",   `$${((data.rev||0)/1000).toFixed(0)}K`,      "#34d399"],
          ["Pipeline",        `$${((data.pipeline||0)/1000).toFixed(0)}K`, "#38bdf8"],
          ["Win Rate",        `${data.winRate||0}%`,                        "#a78bfa"],
          ["Consultants",     data.activeConsultants||0,                    "#f59e0b"],
        ].map(([l,v,col])=>(
          <div key={l} className="card" style={{padding:"12px 14px",textAlign:"center"}}>
            <div style={{fontSize:9,color:"#3d5a7a",textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>{l}</div>
            <div style={{fontSize:22,fontWeight:800,color:col}}>{v}</div>
          </div>
        ))}
      </div>

      {/* Prompt to run analysis */}
      {!insight && !loading && (
        <div className="card" style={{padding:"40px",textAlign:"center",color:"#3d5a7a"}}>
          <div style={{fontSize:40,marginBottom:12}}>🏆</div>
          <div style={{fontSize:15,fontWeight:700,color:"#e2e8f0",marginBottom:8}}>
            AI Performance Coaching
          </div>
          <div style={{fontSize:12,marginBottom:20,maxWidth:400,margin:"0 auto 20px"}}>
            Click <strong style={{color:"#C9A84C"}}>Run Analysis</strong> to get brutally honest behavioral insights,
            pattern detection, and your #1 action for this week.
          </div>
          <button className="btn bp" style={{fontSize:13,padding:"10px 28px",fontWeight:700}} onClick={analyze}>
            🔍 Run Analysis
          </button>
        </div>
      )}

      {loading && (
        <div className="card" style={{padding:"40px",textAlign:"center"}}>
          <div style={{fontSize:13,color:"#38bdf8"}}>⏳ Analyzing performance patterns...</div>
        </div>
      )}

      {/* ── TEAM LEADERBOARD ── */}
      <div className="card" style={{padding:"16px 18px",marginBottom:14}}>
        <div style={{fontSize:11,fontWeight:700,color:"#e2e8f0",marginBottom:12}}>
          🏆 Team Performance Leaderboard
        </div>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
            <thead>
              <tr style={{borderBottom:"1px solid #1a2d45"}}>
                {["#","Consultant","Role","Util %","Bill Rate","Est Revenue","Cost","Margin"].map(h=>(
                  <th key={h} className="th" style={{padding:"6px 10px",textAlign:h==="#"||h==="Consultant"||h==="Role"?"left":"right",fontSize:9}}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {[...roster].sort((a,b)=>(b.util||0)-(a.util||0)).slice(0,10).map((r,i)=>{
                const util = Math.round((r.util||0)*100);
                const estRev = (r.util||0)*160*12*(r.billRate||0);
                const cost = getEmployeeCost(r);
                const margin = estRev > 0 ? Math.round((estRev-cost)/estRev*100) : 0;
                const utilColor = util>=80?"#34d399":util>=50?"#f59e0b":"#f87171";
                const marginColor = margin>=30?"#34d399":margin>=10?"#f59e0b":"#f87171";
                return (
                  <tr key={r.id} style={{borderBottom:"1px solid #0a1626",background:i===0?"#021f1420":""}}>
                    <td style={{padding:"7px 10px",color:i===0?"#f59e0b":"#3d5a7a",fontWeight:i===0?700:400}}>
                      {i===0?"🥇":i===1?"🥈":i===2?"🥉":(i+1)}
                    </td>
                    <td style={{padding:"7px 10px",color:"#e2e8f0",fontWeight:600}}>{r.name}</td>
                    <td style={{padding:"7px 10px",color:"#64748b",fontSize:10}}>{r.role}</td>
                    <td style={{padding:"7px 10px",textAlign:"right",color:utilColor,fontWeight:700}}>{util}%</td>
                    <td style={{padding:"7px 10px",textAlign:"right",color:"#94a3b8"}}>${r.billRate||0}/hr</td>
                    <td style={{padding:"7px 10px",textAlign:"right",color:"#38bdf8",fontFamily:"monospace"}}>
                      ${Math.round(estRev/1000)}K
                    </td>
                    <td style={{padding:"7px 10px",textAlign:"right",color:"#475569",fontFamily:"monospace"}}>
                      ${Math.round(cost/1000)}K
                    </td>
                    <td style={{padding:"7px 10px",textAlign:"right",color:marginColor,fontWeight:700}}>
                      {margin}%
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        {/* Top performer badge */}
        {roster.length > 0 && (() => {
          const top = [...roster].sort((a,b)=>(b.util||0)-(a.util||0))[0];
          const low = [...roster].sort((a,b)=>(a.util||0)-(b.util||0))[0];
          return (
            <div style={{display:"flex",gap:10,marginTop:12,flexWrap:"wrap"}}>
              <div style={{padding:"6px 12px",background:"#021f14",border:"1px solid #15803d44",borderRadius:6,fontSize:10}}>
                <span style={{color:"#64748b"}}>🏆 Top performer: </span>
                <span style={{color:"#34d399",fontWeight:700}}>{top.name}</span>
                <span style={{color:"#475569"}}> ({Math.round((top.util||0)*100)}% util)</span>
              </div>
              {low.util < 0.3 && (
                <div style={{padding:"6px 12px",background:"#1a0808",border:"1px solid #f8717144",borderRadius:6,fontSize:10}}>
                  <span style={{color:"#64748b"}}>⚠️ Needs attention: </span>
                  <span style={{color:"#f87171",fontWeight:700}}>{low.name}</span>
                  <span style={{color:"#475569"}}> ({Math.round((low.util||0)*100)}% util — bench risk)</span>
                </div>
              )}
            </div>
          );
        })()}
      </div>

      {/* AI Coaching Results */}
      {insight && (
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>

          {/* Score + Headline */}
          <div className="card" style={{padding:"20px 22px",gridColumn:"1/-1",
            background:`linear-gradient(135deg,#070c18,#0c1a2e)`}}>
            <div style={{display:"flex",alignItems:"center",gap:20}}>
              <div style={{textAlign:"center",flexShrink:0}}>
                <div style={{fontSize:48,fontWeight:900,color:scoreColor(insight.score),lineHeight:1}}>
                  {insight.score}
                </div>
                <div style={{fontSize:10,color:scoreColor(insight.score),fontWeight:700}}>
                  / 10
                </div>
                <div style={{fontSize:11,color:scoreColor(insight.score),fontWeight:700,marginTop:4}}>
                  {insight.scoreLabel}
                </div>
              </div>
              <div style={{flex:1}}>
                <div style={{fontSize:11,color:"#3d5a7a",textTransform:"uppercase",letterSpacing:.5,marginBottom:6}}>
                  AI Assessment
                </div>
                <div style={{fontSize:16,fontWeight:700,color:"#e2e8f0",lineHeight:1.4}}>
                  {insight.headline}
                </div>
              </div>
            </div>
          </div>

          {/* Top Action */}
          <div className="card" style={{padding:"18px 20px",gridColumn:"1/-1",
            background:"#021f14",border:"1px solid #15803d44"}}>
            <div style={{fontSize:10,color:"#34d399",textTransform:"uppercase",letterSpacing:.5,marginBottom:6,fontWeight:700}}>
              🎯 Your #1 Action This Week
            </div>
            <div style={{fontSize:14,color:"#4ade80",fontWeight:700,lineHeight:1.5}}>
              {insight.topAction}
            </div>
          </div>

          {/* Strengths */}
          <div className="card" style={{padding:"18px 20px"}}>
            <div style={{fontSize:10,color:"#34d399",textTransform:"uppercase",letterSpacing:.5,marginBottom:10,fontWeight:700}}>
              ✅ What You're Doing Well
            </div>
            {(insight.strengths||[]).map((s,i)=>(
              <div key={i} style={{display:"flex",gap:8,marginBottom:8,fontSize:11,color:"#94a3b8",lineHeight:1.5}}>
                <span style={{color:"#34d399",flexShrink:0}}>✓</span>{s}
              </div>
            ))}
          </div>

          {/* Gaps */}
          <div className="card" style={{padding:"18px 20px"}}>
            <div style={{fontSize:10,color:"#f87171",textTransform:"uppercase",letterSpacing:.5,marginBottom:10,fontWeight:700}}>
              ⚠ Critical Gaps
            </div>
            {(insight.gaps||[]).map((g,i)=>(
              <div key={i} style={{display:"flex",gap:8,marginBottom:8,fontSize:11,color:"#94a3b8",lineHeight:1.5}}>
                <span style={{color:"#f87171",flexShrink:0}}>✗</span>{g}
              </div>
            ))}
          </div>

          {/* Behavioral Patterns */}
          <div className="card" style={{padding:"18px 20px"}}>
            <div style={{fontSize:10,color:"#a78bfa",textTransform:"uppercase",letterSpacing:.5,marginBottom:10,fontWeight:700}}>
              🧠 Behavior Patterns Detected
            </div>
            {(insight.patterns||[]).map((p,i)=>(
              <div key={i} style={{padding:"8px 10px",background:"#0d0b1a",borderRadius:6,
                border:"1px solid #1e1b4b",marginBottom:6,fontSize:11,color:"#c4b5fd",lineHeight:1.5}}>
                {p}
              </div>
            ))}
          </div>

          {/* Quick Wins */}
          <div className="card" style={{padding:"18px 20px"}}>
            <div style={{fontSize:10,color:"#f59e0b",textTransform:"uppercase",letterSpacing:.5,marginBottom:10,fontWeight:700}}>
              ⚡ Quick Wins (This Week)
            </div>
            {(insight.quickWins||[]).map((q,i)=>(
              <div key={i} style={{display:"flex",gap:8,marginBottom:8,fontSize:11,color:"#94a3b8",lineHeight:1.5}}>
                <span style={{color:"#f59e0b",flexShrink:0}}>{i+1}.</span>{q}
              </div>
            ))}
          </div>

          {/* Benchmark + Forecast */}
          <div className="card" style={{padding:"18px 20px",gridColumn:"1/-1"}}>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
              <div>
                <div style={{fontSize:10,color:"#38bdf8",textTransform:"uppercase",letterSpacing:.5,marginBottom:8,fontWeight:700}}>
                  📊 Industry Benchmark
                </div>
                <div style={{fontSize:12,color:"#94a3b8",lineHeight:1.6}}>{insight.benchmark}</div>
              </div>
              <div>
                <div style={{fontSize:10,color:"#fb923c",textTransform:"uppercase",letterSpacing:.5,marginBottom:8,fontWeight:700}}>
                  🔮 30-Day Forecast (if nothing changes)
                </div>
                <div style={{fontSize:12,color:"#94a3b8",lineHeight:1.6}}>{insight.forecast}</div>
              </div>
            </div>
          </div>

          {/* Top Performer Behaviors */}
          {(insight.topPerformerBehaviors||[]).length > 0 && (
            <div className="card" style={{padding:"18px 20px",gridColumn:"1/-1",border:"1px solid #f59e0b44"}}>
              <div style={{fontSize:10,color:"#f59e0b",textTransform:"uppercase",letterSpacing:.5,marginBottom:10,fontWeight:700}}>
                🌟 What Top Performers Do Differently
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
                {insight.topPerformerBehaviors.map((b,i)=>(
                  <div key={i} style={{padding:"10px 12px",background:"#1a1000",border:"1px solid #d9770644",borderRadius:8}}>
                    <div style={{fontSize:9,color:"#f59e0b",fontWeight:700,marginBottom:4}}>Behavior {i+1}</div>
                    <div style={{fontSize:11,color:"#fcd34d",lineHeight:1.4}}>{b}</div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* 4-Week Coaching Plan */}
          {insight.coachingPlan && (
            <div className="card" style={{padding:"18px 20px",gridColumn:"1/-1",background:"#070c18",border:"1px solid #0369a144"}}>
              <div style={{fontSize:10,color:"#38bdf8",textTransform:"uppercase",letterSpacing:.5,marginBottom:12,fontWeight:700}}>
                📅 4-Week Coaching Plan
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8}}>
                {Object.entries(insight.coachingPlan).map(([week,action])=>(
                  <div key={week} style={{padding:"10px 12px",background:"#060d1c",borderRadius:8,border:"1px solid #1e3a5f"}}>
                    <div style={{fontSize:9,color:"#3d5a7a",fontWeight:700,marginBottom:4,textTransform:"uppercase"}}>{week}</div>
                    <div style={{fontSize:11,color:"#94a3b8",lineHeight:1.4}}>{action}</div>
                  </div>
                ))}
              </div>
            </div>
          )}

        </div>
      )}

      {/* ── LEADERBOARD VIEW ── */}
      {view==="leaderboard" && (
        <div>
          {!leaderboard && !lbLoading && (
            <div className="card" style={{padding:"32px",textAlign:"center"}}>
              <div style={{fontSize:32,marginBottom:10}}>🏆</div>
              <div style={{fontSize:13,color:"#94a3b8",marginBottom:16}}>
                AI ranks your team, identifies top performers, at-risk consultants, and coaching opportunities
              </div>
              <button className="btn bp" style={{fontSize:13,padding:"10px 28px"}} onClick={runLeaderboard}>
                🏆 Generate Team Leaderboard
              </button>
            </div>
          )}
          {lbLoading && <div className="card" style={{padding:24,textAlign:"center",color:"#475569",fontSize:12}}>🏆 Ranking team performance...</div>}
          {leaderboard && !leaderboard.error && (() => {
            const lb = leaderboard;
            return (
              <div>
                {/* Team summary */}
                <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:14}}>
                  {[
                    {l:"Team Size",        v:lb.metrics?.length||0,                      c:"#38bdf8"},
                    {l:"Avg Utilisation",  v:(lb.avgUtil||0)+"%",                         c:lb.avgUtil>75?"#34d399":lb.avgUtil>50?"#f59e0b":"#f87171"},
                    {l:"Avg Margin",       v:(lb.avgMargin||0)+"%",                       c:lb.avgMargin>40?"#34d399":lb.avgMargin>25?"#f59e0b":"#f87171"},
                    {l:"Team Revenue/yr",  v:"$"+Math.round((lb.totalRevenue||0)/1000)+"K", c:"#a78bfa"},
                  ].map(s=>(
                    <div key={s.l} className="card" style={{padding:"10px 14px",textAlign:"center"}}>
                      <div style={{fontSize:20,fontWeight:800,color:s.c,fontFamily:"'DM Mono',monospace"}}>{s.v}</div>
                      <div style={{fontSize:9,color:"#475569",marginTop:2,textTransform:"uppercase",letterSpacing:.5}}>{s.l}</div>
                    </div>
                  ))}
                </div>

                {/* AI team insight */}
                <div style={{padding:"12px 16px",background:"#0c1a2e",border:"1px solid #0369a144",borderRadius:10,marginBottom:14}}>
                  <div style={{fontSize:9,color:"#3d5a7a",marginBottom:4,textTransform:"uppercase",letterSpacing:.5}}>💡 Team Assessment</div>
                  <div style={{fontSize:13,fontWeight:700,color:"#38bdf8",marginBottom:4}}>{lb.teamInsight}</div>
                  <div style={{fontSize:11,color:"#64748b"}}>{lb.benchmarkVsMarket}</div>
                </div>

                {/* Consultant ranking table */}
                <div className="card" style={{padding:"14px 16px",marginBottom:12,overflowX:"auto"}}>
                  <div style={{fontSize:11,fontWeight:700,color:"#3d5a7a",marginBottom:10,textTransform:"uppercase",letterSpacing:.5}}>
                    👥 Consultant Rankings
                  </div>
                  <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
                    <thead>
                      <tr style={{borderBottom:"1px solid #1a2d45"}}>
                        {["#","Consultant","Role","Util","Bill Rate","Revenue/yr","Margin","Type"].map(h=>(
                          <th key={h} className="th" style={{padding:"6px 10px",textAlign:h==="#"||h==="Util"||h==="Bill Rate"||h==="Revenue/yr"||h==="Margin"?"center":"left"}}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {(lb.metrics||[]).map((m,i)=>{
                        const isTop = (lb.topPerformers||[]).some(t=>t.name===m.name);
                        const isRisk = (lb.atRisk||[]).some(r=>r.name===m.name);
                        return (
                          <tr key={m.name} style={{borderBottom:"1px solid #0a1626",background:isTop?"#021f1488":isRisk?"#1a080888":""}}>
                            <td style={{padding:"7px 10px",textAlign:"center",color:"#334155",fontWeight:700}}>{i+1}</td>
                            <td style={{padding:"7px 10px"}}>
                              <div style={{display:"flex",alignItems:"center",gap:6}}>
                                {isTop&&<span style={{fontSize:10}}>⭐</span>}
                                {isRisk&&<span style={{fontSize:10}}>⚠️</span>}
                                <span style={{color:"#e2e8f0",fontWeight:600}}>{m.name}</span>
                              </div>
                            </td>
                            <td style={{padding:"7px 10px",color:"#64748b",fontSize:10}}>{m.role}</td>
                            <td style={{padding:"7px 10px",textAlign:"center",color:m.util>75?"#34d399":m.util>50?"#f59e0b":"#f87171",fontWeight:700}}>{m.util}%</td>
                            <td style={{padding:"7px 10px",textAlign:"center",color:"#38bdf8",fontFamily:"monospace"}}>${m.billRate}/hr</td>
                            <td style={{padding:"7px 10px",textAlign:"center",color:"#a78bfa",fontFamily:"monospace",fontWeight:700}}>${Math.round(m.revenue/1000)}K</td>
                            <td style={{padding:"7px 10px",textAlign:"center",color:m.margin>40?"#34d399":m.margin>25?"#f59e0b":"#f87171"}}>{m.margin}%</td>
                            <td style={{padding:"7px 10px",fontSize:9,color:"#475569"}}>{m.type}</td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>

                {/* Top performers + At Risk side by side */}
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:12}}>
                  <div className="card" style={{padding:"14px 16px"}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#34d399",marginBottom:10}}>⭐ Top Performers</div>
                    {(lb.topPerformers||[]).map((t,i)=>(
                      <div key={i} style={{marginBottom:10,padding:"10px 12px",background:"#021f14",border:"1px solid #15803d44",borderRadius:8}}>
                        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
                          <span style={{fontSize:12,fontWeight:700,color:"#4ade80"}}>{t.name}</span>
                          <span style={{fontSize:11,fontWeight:800,color:"#34d399",fontFamily:"monospace"}}>{t.score}/100</span>
                        </div>
                        <div style={{fontSize:10,color:"#64748b"}}>{t.why}</div>
                      </div>
                    ))}
                  </div>
                  <div className="card" style={{padding:"14px 16px"}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#f87171",marginBottom:10}}>⚠️ At Risk / Needs Coaching</div>
                    {(lb.atRisk||[]).map((r,i)=>(
                      <div key={i} style={{marginBottom:10,padding:"10px 12px",background:"#1a0808",border:"1px solid #dc262644",borderRadius:8}}>
                        <div style={{fontSize:12,fontWeight:700,color:"#f87171",marginBottom:3}}>{r.name}</div>
                        <div style={{fontSize:10,color:"#f87171",marginBottom:3}}>{r.risk}</div>
                        <div style={{fontSize:10,color:"#34d399"}}>→ {r.action}</div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Quick win + revenue opportunity */}
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                  <div style={{padding:"10px 14px",background:"#021f14",border:"1px solid #15803d44",borderRadius:8}}>
                    <div style={{fontSize:9,color:"#3d5a7a",marginBottom:3,textTransform:"uppercase"}}>⚡ Quick Win This Week</div>
                    <div style={{fontSize:11,color:"#34d399",lineHeight:1.5}}>{lb.quickWin}</div>
                  </div>
                  <div style={{padding:"10px 14px",background:"#0d0b1a",border:"1px solid #7c3aed44",borderRadius:8}}>
                    <div style={{fontSize:9,color:"#3d5a7a",marginBottom:3,textTransform:"uppercase"}}>💰 Revenue Opportunity</div>
                    <div style={{fontSize:11,color:"#a78bfa",lineHeight:1.5}}>{lb.revenueOpportunity}</div>
                  </div>
                </div>

                <button className="btn bg" style={{fontSize:10,marginTop:12}} onClick={()=>setLeaderboard(null)}>
                  ↺ Re-run Analysis
                </button>
              </div>
            );
          })()}
        </div>
      )}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// ⚡ AUTONOMOUS WORKFLOWS — Auto-SOW • Auto-Follow-Up • Auto-AR-Escalation
// Watches real data, fires AI-powered actions automatically, logs everything
// ══════════════════════════════════════════════════════════════════════════════
function AutoWorkflows({ crmDeals, setCrmDeals, clients, roster, finInvoices, proposals, setProposals, authProfile }) {
  const TODAY = new Date().toISOString().split("T")[0];
  const YEAR  = new Date().getFullYear();

  // ── Workflow log (persisted in localStorage) ─────────────────────────────
  const [wfLog, setWfLog] = useState(() => {
    try { return JSON.parse(localStorage.getItem("zt-wf-log") || "[]"); } catch { return []; }
  });
  const addLog = (entry) => {
    const e = { ...entry, id: "wf-"+Date.now(), ts: new Date().toLocaleString() };
    setWfLog(prev => { const next = [e,...prev].slice(0,100); localStorage.setItem("zt-wf-log",JSON.stringify(next)); return next; });
    return e;
  };

  // ── UI state ──────────────────────────────────────────────────────────────
  const [activeTab,   setActiveTab]   = useState("rules");
  const [running,     setRunning]     = useState({});
  const [preview,     setPreview]     = useState(null); // { type, content, deal/inv }
  const [showLog,     setShowLog]     = useState(false);
  const [fired,       setFired]       = useState(() => {
    try { return JSON.parse(localStorage.getItem("zt-wf-fired") || "{}"); } catch { return {}; }
  });
  const markFired = (key) => setFired(prev => {
    const next = {...prev,[key]:TODAY}; localStorage.setItem("zt-wf-fired",JSON.stringify(next)); return next;
  });

  // ── Workflow definitions ──────────────────────────────────────────────────
  const WORKFLOWS = [
    {
      id: "wf-closedwon-sow",
      icon: "📄",
      title: "Auto-Draft SOW on Deal Close",
      trigger: "When deal moves to Closed Won",
      action: "AI generates a full SOW draft + notifies team",
      status: "active",
      color: "#34d399",
      bg: "#021f14",
      border: "#15803d44",
    },
    {
      id: "wf-stale-followup",
      icon: "📧",
      title: "Stale Deal Follow-Up Email",
      trigger: "When deal has no activity for 7+ days",
      action: "AI drafts personalised follow-up email for each stale deal",
      status: "active",
      color: "#f59e0b",
      bg: "#1a1000",
      border: "#d9770644",
    },
    {
      id: "wf-ar-escalation",
      icon: "💰",
      title: "AR Overdue Escalation",
      trigger: "When invoice is 30+ days overdue",
      action: "AI drafts escalation message to client with payment urgency",
      status: "active",
      color: "#f87171",
      bg: "#1a0808",
      border: "#dc262644",
    },
    {
      id: "wf-bench-alert",
      icon: "🪑",
      title: "Bench Burn Alert",
      trigger: "When consultant utilisation drops below 20% for 2+ weeks",
      action: "AI suggests redeployment options + flags in AI COO",
      status: "active",
      color: "#a78bfa",
      bg: "#0d0b1a",
      border: "#7c3aed44",
    },
    {
      id: "wf-deal-accelerator",
      icon: "🎯",
      title: "Deal Stage Stall Alert",
      trigger: "When deal stays in same stage for 14+ days",
      action: "AI recommends next-best-action and flags to owner",
      status: "active",
      color: "#38bdf8",
      bg: "#0c1a2e",
      border: "#0369a144",
    },
  ];

  // ── Detect trigger conditions ─────────────────────────────────────────────
  const staleDays = 7;
  const arOverdueDays = 30;

  const closedWonDeals  = crmDeals.filter(d => d.stage === "closed-won");
  const staleDeals      = crmDeals.filter(d => {
    if (d.stage === "closed-won" || d.stage === "closed-lost") return false;
    const last = d.lastActivity || d.updatedAt || d.createdAt || "2026-01-01";
    return (new Date(TODAY) - new Date(last)) / 86400000 > staleDays;
  });
  const overdueInvoices = finInvoices.filter(inv => {
    const due = inv.dueDate || inv.date;
    if (!due || inv.status === "paid") return false;
    return (new Date(TODAY) - new Date(due)) / 86400000 > arOverdueDays;
  });

  const triggers = [
    { wfId:"wf-closedwon-sow",    count: closedWonDeals.length,  items: closedWonDeals,  label:"closed-won deals" },
    { wfId:"wf-stale-followup",   count: staleDeals.length,      items: staleDeals,      label:"stale deals" },
    { wfId:"wf-ar-escalation",    count: overdueInvoices.length, items: overdueInvoices, label:"overdue invoices" },
    { wfId:"wf-bench-alert",      count: 0, items: [], label:"bench alerts" },
    { wfId:"wf-deal-accelerator", count: staleDeals.filter(d=>{
        const last = d.lastActivity||d.updatedAt||"2026-01-01";
        return (new Date(TODAY)-new Date(last))/86400000 > 14;
      }).length, items:[], label:"stalled deals" },
  ];
  const totalFiring = triggers.reduce((s,t) => s + t.count, 0);

  // ── AI action generators ──────────────────────────────────────────────────
  const runClosedWonSOW = async (deal) => {
    const key = `wf-closedwon-sow-${deal.id}`;
    if (fired[key]) return;
    setRunning(r => ({...r, [key]: true}));
    const client = clients.find(c => c.id === deal.clientId || c.name === deal.clientName) || {};
    const prompt = `You are a SOW writer for Ziksatech, a SAP consulting firm. Generate a professional Statement of Work for this newly closed deal.

DEAL: ${deal.name||deal.title||"Untitled"} | Client: ${deal.clientName||client.name||"Client"} | Value: $${(deal.value||0).toLocaleString()} | Close Date: ${TODAY}
DESCRIPTION: ${deal.notes||deal.description||"SAP consulting engagement"}
CONSULTANTS AVAILABLE: ${roster.filter(r=>r.type!=="FTE"||r.util<90).slice(0,3).map(r=>r.name+" ("+r.role+")").join(", ")}

Generate a concise SOW with: 1) Scope of Work, 2) Key Deliverables (3-4 items), 3) Timeline (milestones), 4) Team Composition, 5) Assumptions & Dependencies. Keep it under 400 words.

Respond ONLY with JSON: {"scope":"...","deliverables":["...","...","..."],"timeline":"...","team":"...","assumptions":"...","title":"..."}`;
    try {
      const resp = await fetch("/api/claude", { method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:2000, messages:[{role:"user",content:prompt}] })
      });
      const data = await resp.json();
      const parsed = extractJSON(data.content?.[0]?.text||"{}");
      setPreview({ type:"sow", deal, content: parsed });
      addLog({ type:"sow", icon:"📄", title:`SOW drafted — ${deal.clientName||"Client"}`, detail:`$${(deal.value||0).toLocaleString()} deal · ${parsed.deliverables?.length||0} deliverables`, status:"success" });
      markFired(key);
    } catch(e) {
      addLog({ type:"sow", icon:"❌", title:`SOW failed — ${deal.clientName}`, detail:e.message, status:"error" });
    }
    setRunning(r => ({...r,[key]:false}));
  };

  const runStaleFollowUp = async (deal) => {
    const key = `wf-stale-followup-${deal.id}`;
    if (fired[key]) return;
    setRunning(r => ({...r,[key]:true}));
    const daysSince = Math.floor((new Date(TODAY)-new Date(deal.lastActivity||deal.updatedAt||"2026-01-01"))/86400000);
    const prompt = `You are Manju Murthy, Managing Partner at Ziksatech, a SAP consulting firm specializing in Utilities and BRIM.

Write a brief, warm follow-up email for this stale deal. Sound natural — not templated. Reference their specific situation.

DEAL: ${deal.name||deal.title} | Stage: ${deal.stage} | Value: $${(deal.value||0).toLocaleString()} | Days since contact: ${daysSince}
CLIENT: ${deal.clientName} | Notes: ${deal.notes||"SAP consulting engagement"}
NEXT STEP WAS: ${deal.nextStep||"Follow up on proposal"}

Keep it to 3-4 sentences. Professional but personable.
Respond ONLY with JSON: {"subject":"...","body":"...","callToAction":"..."}`;
    try {
      const resp = await fetch("/api/claude", { method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:1000, messages:[{role:"user",content:prompt}] })
      });
      const data = await resp.json();
      const parsed = extractJSON(data.content?.[0]?.text||"{}");
      setPreview({ type:"email", deal, content:parsed });
      addLog({ type:"email", icon:"📧", title:`Follow-up drafted — ${deal.clientName}`, detail:`${daysSince} days stale · ${deal.stage}`, status:"success" });
      markFired(key);
    } catch(e) {
      addLog({ type:"email", icon:"❌", title:`Follow-up failed — ${deal.clientName}`, detail:e.message, status:"error" });
    }
    setRunning(r => ({...r,[key]:false}));
  };

  const runARescalation = async (inv) => {
    const key = `wf-ar-escalation-${inv.id}`;
    if (fired[key]) return;
    setRunning(r => ({...r,[key]:true}));
    const daysOver = Math.floor((new Date(TODAY)-new Date(inv.dueDate||inv.date))/86400000);
    const prompt = `You are Manju Murthy, Managing Partner at Ziksatech. Write a professional but firm payment escalation message.

INVOICE: ${inv.id} | Client: ${inv.clientName||inv.client} | Amount: $${(inv.amount||0).toLocaleString()} | ${daysOver} days overdue | Due: ${inv.dueDate||inv.date}

Write a short, firm but professional email requesting immediate payment. Mention consequences (work pause) if not resolved within 5 business days. Keep it factual.
Respond ONLY with JSON: {"subject":"...","body":"...","urgency":"HIGH"}`;
    try {
      const resp = await fetch("/api/claude", { method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:800, messages:[{role:"user",content:prompt}] })
      });
      const data = await resp.json();
      const parsed = extractJSON(data.content?.[0]?.text||"{}");
      setPreview({ type:"ar", inv, content:parsed });
      addLog({ type:"ar", icon:"💰", title:`AR escalation drafted — ${inv.clientName||inv.client}`, detail:`$${(inv.amount||0).toLocaleString()} · ${daysOver} days overdue`, status:"success" });
      markFired(key);
    } catch(e) {
      addLog({ type:"ar", icon:"❌", title:`AR escalation failed`, detail:e.message, status:"error" });
    }
    setRunning(r => ({...r,[key]:false}));
  };

  // ── Run All Triggered Workflows ───────────────────────────────────────────
  const runAll = async () => {
    for (const deal of closedWonDeals.slice(0,3)) await runClosedWonSOW(deal);
    for (const deal of staleDeals.slice(0,3)) await runStaleFollowUp(deal);
    for (const inv of overdueInvoices.slice(0,3)) await runARescalation(inv);
  };

  return (
    <div>
      <PH title="⚡ Autonomous Workflows" sub="AI takes action automatically — SOW generation, follow-ups, AR escalation, bench alerts">
        <div style={{display:"flex",gap:8}}>
          <button className="btn bg" style={{fontSize:11}} onClick={()=>setShowLog(!showLog)}>
            📋 {wfLog.length} Actions Taken
          </button>
          {totalFiring > 0 && (
            <button className="btn bp" style={{fontSize:12,fontWeight:700}} onClick={runAll}>
              ⚡ Run All ({totalFiring} triggered)
            </button>
          )}
        </div>
      </PH>

      {/* ── STATS ROW ── */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
        {[
          {l:"Active Rules",    v:WORKFLOWS.length,       c:"#38bdf8"},
          {l:"Triggered Now",   v:totalFiring,            c:totalFiring>0?"#f87171":"#34d399"},
          {l:"Actions Today",   v:wfLog.filter(e=>e.ts.includes(new Date().toLocaleDateString())).length, c:"#f59e0b"},
          {l:"Total Automated", v:wfLog.length,           c:"#a78bfa"},
        ].map(s=>(
          <div key={s.l} className="card" style={{padding:"12px 16px",textAlign:"center"}}>
            <div style={{fontSize:22,fontWeight:800,color:s.c,fontFamily:"'DM Mono',monospace"}}>{s.v}</div>
            <div style={{fontSize:9,color:"#3d5a7a",textTransform:"uppercase",letterSpacing:.5,marginTop:2}}>{s.l}</div>
          </div>
        ))}
      </div>

      {/* ── WORKFLOW RULES ── */}
      <div className="card" style={{padding:"16px 18px",marginBottom:14}}>
        <div style={{fontSize:12,fontWeight:700,color:"#3d5a7a",marginBottom:12,textTransform:"uppercase",letterSpacing:.5}}>
          Active Automation Rules
        </div>
        {WORKFLOWS.map(wf => {
          const trig = triggers.find(t=>t.wfId===wf.id)||{count:0,items:[]};
          return (
            <div key={wf.id} style={{display:"flex",alignItems:"center",gap:14,padding:"12px 14px",marginBottom:8,
              background:wf.bg,border:`1px solid ${wf.border}`,borderRadius:10}}>
              <div style={{fontSize:24,flexShrink:0}}>{wf.icon}</div>
              <div style={{flex:1}}>
                <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:2}}>
                  <span style={{fontSize:12,fontWeight:700,color:"#e2e8f0"}}>{wf.title}</span>
                  {trig.count > 0 && (
                    <span style={{background:"#f87171",color:"#fff",fontSize:9,fontWeight:700,
                      borderRadius:10,padding:"1px 6px"}}>{trig.count} ACTIVE</span>
                  )}
                </div>
                <div style={{fontSize:10,color:"#64748b"}}>
                  🔔 <strong>Trigger:</strong> {wf.trigger}
                </div>
                <div style={{fontSize:10,color:"#64748b"}}>
                  🤖 <strong>Action:</strong> {wf.action}
                </div>
              </div>
              <div style={{display:"flex",gap:6,flexShrink:0}}>
                <div style={{width:8,height:8,borderRadius:"50%",background:wf.color,marginTop:4}}/>
                <span style={{fontSize:10,color:wf.color,fontWeight:700,textTransform:"uppercase"}}>{wf.status}</span>
              </div>
            </div>
          );
        })}
      </div>

      {/* ── TRIGGERED ITEMS ── */}
      {totalFiring > 0 && (
        <div className="card" style={{padding:"16px 18px",marginBottom:14,border:"1px solid #f8717144"}}>
          <div style={{fontSize:12,fontWeight:700,color:"#f87171",marginBottom:12}}>
            ⚡ Currently Triggered — {totalFiring} items need automated action
          </div>

          {/* Closed Won → SOW */}
          {closedWonDeals.length > 0 && (
            <div style={{marginBottom:14}}>
              <div style={{fontSize:11,fontWeight:700,color:"#34d399",marginBottom:6}}>📄 SOW Generation ({closedWonDeals.length} deals)</div>
              {closedWonDeals.slice(0,5).map(deal => {
                const k = `wf-closedwon-sow-${deal.id}`;
                return (
                  <div key={deal.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",
                    padding:"8px 12px",background:"#021f14",borderRadius:8,marginBottom:6,border:"1px solid #15803d44"}}>
                    <div>
                      <div style={{fontSize:11,fontWeight:700,color:"#e2e8f0"}}>{deal.clientName||deal.name}</div>
                      <div style={{fontSize:10,color:"#64748b"}}>${(deal.value||0).toLocaleString()} · closed-won</div>
                    </div>
                    <button className="btn bg" style={{fontSize:10,padding:"4px 10px"}}
                      disabled={!!running[k]||!!fired[k]}
                      onClick={()=>runClosedWonSOW(deal)}>
                      {running[k]?"⏳...":fired[k]?"✅ Done":"📄 Draft SOW"}
                    </button>
                  </div>
                );
              })}
            </div>
          )}

          {/* Stale Deals → Follow-Up */}
          {staleDeals.length > 0 && (
            <div style={{marginBottom:14}}>
              <div style={{fontSize:11,fontWeight:700,color:"#f59e0b",marginBottom:6}}>📧 Follow-Up Emails ({staleDeals.length} stale deals)</div>
              {staleDeals.slice(0,5).map(deal => {
                const k = `wf-stale-followup-${deal.id}`;
                const daysSince = Math.floor((new Date(TODAY)-new Date(deal.lastActivity||deal.updatedAt||"2026-01-01"))/86400000);
                return (
                  <div key={deal.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",
                    padding:"8px 12px",background:"#1a1000",borderRadius:8,marginBottom:6,border:"1px solid #d9770644"}}>
                    <div>
                      <div style={{fontSize:11,fontWeight:700,color:"#e2e8f0"}}>{deal.clientName||deal.name}</div>
                      <div style={{fontSize:10,color:"#64748b"}}>{deal.stage} · {daysSince}d no activity · ${(deal.value||0).toLocaleString()}</div>
                    </div>
                    <button className="btn bg" style={{fontSize:10,padding:"4px 10px"}}
                      disabled={!!running[k]||!!fired[k]}
                      onClick={()=>runStaleFollowUp(deal)}>
                      {running[k]?"⏳...":fired[k]?"✅ Done":"📧 Draft Email"}
                    </button>
                  </div>
                );
              })}
            </div>
          )}

          {/* Overdue AR → Escalation */}
          {overdueInvoices.length > 0 && (
            <div style={{marginBottom:6}}>
              <div style={{fontSize:11,fontWeight:700,color:"#f87171",marginBottom:6}}>💰 AR Escalations ({overdueInvoices.length} overdue)</div>
              {overdueInvoices.slice(0,5).map(inv => {
                const k = `wf-ar-escalation-${inv.id}`;
                const daysOver = Math.floor((new Date(TODAY)-new Date(inv.dueDate||inv.date))/86400000);
                return (
                  <div key={inv.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",
                    padding:"8px 12px",background:"#1a0808",borderRadius:8,marginBottom:6,border:"1px solid #dc262644"}}>
                    <div>
                      <div style={{fontSize:11,fontWeight:700,color:"#e2e8f0"}}>{inv.clientName||inv.client} — {inv.id}</div>
                      <div style={{fontSize:10,color:"#64748b"}}>${(inv.amount||0).toLocaleString()} · {daysOver} days overdue</div>
                    </div>
                    <button className="btn bg" style={{fontSize:10,padding:"4px 10px"}}
                      disabled={!!running[k]||!!fired[k]}
                      onClick={()=>runARescalation(inv)}>
                      {running[k]?"⏳...":fired[k]?"✅ Done":"💰 Escalate"}
                    </button>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}

      {totalFiring === 0 && (
        <div className="card" style={{padding:"32px",textAlign:"center",color:"#34d399"}}>
          <div style={{fontSize:32,marginBottom:8}}>✅</div>
          <div style={{fontSize:13,fontWeight:700}}>All workflows clear — no triggers active</div>
          <div style={{fontSize:11,color:"#475569",marginTop:4}}>
            System monitoring: stale deals, overdue AR, closed-won deals, bench burn
          </div>
        </div>
      )}

      {/* ── ACTION LOG ── */}
      {showLog && (
        <div className="card" style={{padding:"16px 18px"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
            <div style={{fontSize:12,fontWeight:700,color:"#e2e8f0"}}>📋 Workflow Action Log</div>
            <button className="btn bg" style={{fontSize:10}} onClick={()=>{setWfLog([]);localStorage.removeItem("zt-wf-log");}}>
              Clear Log
            </button>
          </div>
          {wfLog.length === 0 ? (
            <div style={{textAlign:"center",color:"#334155",padding:20,fontSize:11}}>No actions taken yet</div>
          ) : wfLog.map(e=>(
            <div key={e.id} style={{display:"flex",gap:10,padding:"8px 0",borderBottom:"1px solid #0a1626"}}>
              <div style={{fontSize:18,flexShrink:0}}>{e.icon}</div>
              <div style={{flex:1}}>
                <div style={{fontSize:11,fontWeight:700,color:e.status==="success"?"#34d399":"#f87171"}}>{e.title}</div>
                <div style={{fontSize:10,color:"#475569"}}>{e.detail}</div>
              </div>
              <div style={{fontSize:9,color:"#334155",flexShrink:0}}>{e.ts}</div>
            </div>
          ))}
        </div>
      )}

      {/* ── PREVIEW MODAL ── */}
      {preview && (
        <div className="modal-bg" onClick={e=>e.target===e.currentTarget&&setPreview(null)}>
          <div className="modal" style={{maxWidth:560,maxHeight:"80vh",overflow:"auto"}}>
            <MH title={preview.type==="sow"?"📄 SOW Draft Ready":preview.type==="email"?"📧 Follow-Up Email Draft":"💰 AR Escalation Draft"} onClose={()=>setPreview(null)}/>

            {preview.type==="sow" && (
              <div>
                <div style={{padding:"10px 14px",background:"#021f14",border:"1px solid #15803d44",borderRadius:8,marginBottom:14}}>
                  <div style={{fontSize:11,fontWeight:700,color:"#4ade80",marginBottom:4}}>
                    {preview.content.title||preview.deal.clientName} — Statement of Work
                  </div>
                  <div style={{fontSize:10,color:"#94a3b8"}}>AI-generated draft · Review before sending</div>
                </div>
                {[
                  ["📋 Scope of Work", preview.content.scope],
                  ["🎯 Key Deliverables", Array.isArray(preview.content.deliverables)?preview.content.deliverables.join("\n• "):preview.content.deliverables],
                  ["📅 Timeline", preview.content.timeline],
                  ["👥 Team", preview.content.team],
                  ["⚠️ Assumptions", preview.content.assumptions],
                ].map(([label,val])=>val&&(
                  <div key={label} style={{marginBottom:12}}>
                    <div style={{fontSize:10,fontWeight:700,color:"#3d5a7a",textTransform:"uppercase",marginBottom:4}}>{label}</div>
                    <div style={{fontSize:11,color:"#cbd5e1",lineHeight:1.6,whiteSpace:"pre-wrap"}}>
                      {Array.isArray(preview.content.deliverables)&&label.includes("Deliver")?"• "+preview.content.deliverables.join("\n• "):val}
                    </div>
                  </div>
                ))}
                <div style={{display:"flex",gap:8,marginTop:16}}>
                  <button className="btn bp" style={{flex:1}} onClick={()=>{
                    if(setProposals) setProposals(p=>[...p,{
                      id:"prop-"+Date.now(), title:preview.content.title||preview.deal.clientName+" SOW",
                      client:preview.deal.clientName, value:preview.deal.value, status:"draft",
                      createdDate:TODAY, content:JSON.stringify(preview.content)
                    }]);
                    addLog({type:"sow",icon:"📥",title:"SOW saved to Proposals",detail:preview.deal.clientName,status:"success"});
                    setPreview(null);
                  }}>📥 Save to Proposals</button>
                  <button className="btn bg" onClick={()=>setPreview(null)}>Close</button>
                </div>
              </div>
            )}

            {(preview.type==="email"||preview.type==="ar") && (
              <div>
                <div style={{marginBottom:12}}>
                  <div style={{fontSize:10,color:"#3d5a7a",marginBottom:4,fontWeight:700,textTransform:"uppercase"}}>Subject</div>
                  <div style={{fontSize:12,fontWeight:700,color:"#e2e8f0",padding:"8px 12px",background:"#070c18",borderRadius:6,border:"1px solid #1a2d45"}}>
                    {preview.content.subject}
                  </div>
                </div>
                <div style={{marginBottom:16}}>
                  <div style={{fontSize:10,color:"#3d5a7a",marginBottom:4,fontWeight:700,textTransform:"uppercase"}}>Body</div>
                  <div style={{fontSize:11,color:"#cbd5e1",lineHeight:1.7,padding:"10px 12px",background:"#070c18",borderRadius:6,
                    border:"1px solid #1a2d45",whiteSpace:"pre-wrap"}}>
                    {preview.content.body}
                  </div>
                </div>
                {preview.content.callToAction && (
                  <div style={{padding:"8px 12px",background:"#0c1a2e",border:"1px solid #0369a144",borderRadius:6,marginBottom:16}}>
                    <span style={{fontSize:10,color:"#64748b"}}>Call to action: </span>
                    <span style={{fontSize:11,color:"#38bdf8"}}>{preview.content.callToAction}</span>
                  </div>
                )}
                <div style={{display:"flex",gap:8}}>
                  <button className="btn bp" style={{flex:1}} onClick={()=>{
                    navigator.clipboard?.writeText(`Subject: ${preview.content.subject}\n\n${preview.content.body}`);
                    addLog({type:preview.type,icon:"📋",title:"Email copied to clipboard",detail:preview.content.subject,status:"success"});
                    setPreview(null);
                  }}>📋 Copy Email</button>
                  <button className="btn bg" onClick={()=>setPreview(null)}>Close</button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

